// Renders the last-N samples table for T2/T3/T5 live feeds. Same shape across
// all three tests so the operator's eye doesn't have to relearn columns.
function _renderComplianceLiveFeed(tbodyId, samples, kind) {
  const tbody = document.getElementById(tbodyId);
  if (!tbody) return;
  if (!Array.isArray(samples) || samples.length === 0) {
    tbody.innerHTML = `<tr class="cmp-live-feed-empty"><td colspan="6">Waiting for first sample…</td></tr>`;
    return;
  }
  // Show newest first so the operator's gaze lands on the freshest data.
  const rows = samples.slice().reverse().map(s => {
    const tsIso = s.ts_ms ? new Date(s.ts_ms).toLocaleTimeString() : "—";
    const fz    = Number(s.freq_hz);
    const fzStr = Number.isFinite(fz) ? fz.toFixed(3) : "—";
    let band = "—", bandClass = "";
    if (Number.isFinite(fz) && fz >= 45 && fz <= 65) {
      if (fz >= 59.7 && fz <= 60.3) { band = "continuous"; bandClass = "ok"; }
      else if (fz >= 58.2 && fz <= 61.8) { band = "withstand"; bandClass = "warn"; }
      else { band = "outside"; bandClass = "fail"; }
    } else if (Number.isFinite(fz)) { band = "unit?"; bandClass = "warn"; }
    const stateRaw = Number(s.state_raw);
    const stateLbl = Number.isFinite(stateRaw) ? `0x${stateRaw.toString(16).toUpperCase().padStart(4, "0")}` : "—";
    const alarms = Number(s.alarm_32) || 0;
    const alarmLbl = alarms === 0
      ? `<span class="cmp-pill ok">clear</span>`
      : `<span class="cmp-pill fail">0x${alarms.toString(16).toUpperCase().padStart(8, "0")}</span>`;
    const pacKw = Number.isFinite(Number(s.pac_w)) ? (Number(s.pac_w) / 1000).toFixed(1) : "—";
    const cols = kind === "t3"
      ? `<td>${tsIso}</td><td>${Number.isFinite(Number(s.cosphi)) ? Number(s.cosphi).toFixed(3) : "—"}</td><td>${Number.isFinite(Number(s.qac_var)) ? (Number(s.qac_var) / 1000).toFixed(1) : "—"}</td><td>${stateLbl}</td><td>${alarmLbl}</td><td>${pacKw}</td>`
      : kind === "t5"
      ? `<td>${tsIso}</td><td>${pacKw}</td><td>—</td><td>${stateLbl}</td><td>${alarmLbl}</td><td>${Number.isFinite(Number(s.iac_avg_a)) ? Number(s.iac_avg_a).toFixed(1) + " A" : "—"}</td>`
      : `<td>${tsIso}</td><td>${fzStr}</td><td><span class="cmp-pill ${bandClass}">${band}</span></td><td>${stateLbl}</td><td>${alarmLbl}</td><td>${pacKw}</td>`;
    return `<tr>${cols}</tr>`;
  }).join("");
  tbody.innerHTML = rows;
}

function _formatMmSs(sec) {
  const s = Math.max(0, Math.floor(sec));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${m}:${String(r).padStart(2, "0")}`;
}

function _updateComplianceProgress(prefix, startedAt, durationSec, sampleTotal, lastSampleTs) {
  const wrap = $(prefix + "ProgressWrap");
  if (!wrap) return;
  wrap.hidden = false;
  const elapsedSec = Math.max(0, (Date.now() - startedAt) / 1000);
  const remainingSec = Math.max(0, durationSec - elapsedSec);
  const pct = durationSec > 0 ? Math.min(100, (elapsedSec / durationSec) * 100) : 0;
  const fill = $(prefix + "ProgressFill"); if (fill) fill.style.width = pct.toFixed(1) + "%";
  const elap = $(prefix + "ProgressElapsed"); if (elap) elap.textContent = `${_formatMmSs(elapsedSec)} elapsed`;
  const rem = $(prefix + "ProgressRemaining"); if (rem) rem.textContent = `${_formatMmSs(remainingSec)} remaining`;
  const tickEl = $(prefix + "ProgressLastTick");
  if (tickEl) {
    if (lastSampleTs) {
      const ageS = Math.max(0, (Date.now() - lastSampleTs) / 1000);
      tickEl.textContent = `last sample ${ageS < 1 ? "<1s" : Math.round(ageS) + "s"} ago · ${sampleTotal} captured`;
      tickEl.className = ageS > 10 ? "cmp-progress-tick stale" : "cmp-progress-tick fresh";
    } else {
      tickEl.textContent = "waiting for first sample…";
      tickEl.className = "cmp-progress-tick stale";
    }
  }
}

async function _onT2Start() {
  // Persist failure reasons in the status pill instead of relying on toasts.
  // Operators were missing the toast and reading "Idle." as if Start had been
  // ignored, which made the test look broken when it was actually a one-line
  // setup miss (no IP resolved, auth key declined, etc).
  const setStatus = (msg) => { const el = $("t2Status"); if (el) el.textContent = msg; };
  const target = _readComplianceTarget("t2");
  if (!target) {
    const inv = $("t2Inv")?.value || "?";
    const ipMap = State?.ipConfig?.inverters || {};
    const ipForInv = ipMap[Number(inv)] || ipMap[String(inv)] || "(none)";
    setStatus(`✗ No IP for inverter #${inv} — IP Config has "${ipForInv}". Fix the IP Config or type the IP manually.`);
    showToast("Pick a valid inverter # / slave (and IP if not auto-resolved).", 3000);
    return;
  }
  const authKey = await _bulkAuthForCompliance("Start T2 freq-withstand on", `inverter ${target.inverter} slave ${target.slave}`);
  if (!authKey) {
    setStatus("✗ Cancelled — bulk-control authorization required.");
    showToast("Cancelled.", 1500);
    return;
  }
  const body = {
    test_kind: "t2_freq_withstand",
    targets: [target],
    operator: "operator",
    authKey,
    params: {
      // Clamp client-side too so the operator sees what's actually used
      // instead of silently relying on the server clamp.
      duration_sec:    Math.max(60, Math.min(7200, Number($("t2Duration")?.value) || 1800)),
      sample_period_s: Math.max(1,  Math.min(60,   Number($("t2Period")?.value)   || 2)),
    },
  };
  setStatus("Starting…");
  const resp = await fetch("/api/compliance/run/start", {
    method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(body),
  }).catch(e => ({ ok: false, status: 0, _err: e.message }));
  if (resp.status === 403) clearBulkAuthCache();   // server rejected our cached key — force re-prompt next click
  const r = resp.json ? await resp.json().catch(() => ({ ok: false, error: resp._err || "parse error" })) : resp;
  if (!r.ok) {
    setStatus(`✗ Start failed: ${r.error || "unknown error"}`);
    showToast(r.error || "Start failed.", 4000);
    return;
  }
  const startedAt = Date.now();
  const durationSec = Number(body.params.duration_sec) || 1800;
  $("t2RunId").textContent = r.run_id;
  $("t2Status").textContent = "Running — capturing live frames…";
  $("t2Start").disabled = true;
  $("t2Abort").disabled = false;
  // Reset feed state so a second run doesn't show last run's data.
  $("t2LiveFeedBody").innerHTML = `<tr class="cmp-live-feed-empty"><td colspan="6">Waiting for first sample…</td></tr>`;
  $("t2Samples").textContent = "0"; $("t2MeanHz").textContent = "—";
  $("t2MinMaxHz").textContent = "—"; $("t2Excursion").textContent = "0 ms";
  $("t2Alarms").textContent = "0";

  _watchComplianceRun(r.run_id, (status, summary, _steps, live) => {
    const tail = (live?.samples_tail) || [];
    const sampleTotal = live?.sample_count_total ?? 0;
    const lastSampleTs = tail.length > 0 ? Number(tail[tail.length - 1].ts_ms) : null;

    // Status pill copy is more informative than the bare run state — gives
    // the operator a one-glance signal for what the gateway is doing right now.
    if (status === "running") {
      const dropped = live?.sample_dropped || 0;
      $("t2Status").textContent = sampleTotal > 0
        ? `Running — ${sampleTotal} samples captured${dropped > 0 ? ` (${dropped} dropped)` : ""}`
        : "Running — waiting for first frame…";
    } else {
      $("t2Status").textContent = status;
    }

    _updateComplianceProgress("t2", startedAt, durationSec, sampleTotal, lastSampleTs);
    _renderComplianceLiveFeed("t2LiveFeedBody", tail, "t2");

    // Mid-run KPI tiles — recomputed from the live tail so the operator sees
    // the dials move every 3 s instead of staring at zeros until finalize().
    if (status === "running" && tail.length > 0) {
      const freqs = tail.map(s => Number(s.freq_hz)).filter(f => Number.isFinite(f) && f >= 45 && f <= 65);
      $("t2Samples").textContent = sampleTotal;
      if (freqs.length > 0) {
        const mean = freqs.reduce((a, b) => a + b, 0) / freqs.length;
        $("t2MeanHz").textContent   = mean.toFixed(3);
        $("t2MinMaxHz").textContent = `${Math.min(...freqs).toFixed(2)} / ${Math.max(...freqs).toFixed(2)} Hz`;
      }
      $("t2Alarms").textContent = tail.reduce((acc, s) => acc + (Number(s.alarm_32) > 0 ? 1 : 0), 0);
    }
    // Final values from authoritative summary once finalize() fires.
    if (summary) {
      $("t2Samples").textContent  = summary.samples ?? 0;
      $("t2MeanHz").textContent   = summary.mean_hz ? Number(summary.mean_hz).toFixed(3) : "—";
      $("t2MinMaxHz").textContent = summary.min_hz != null
        ? `${Number(summary.min_hz).toFixed(2)} / ${Number(summary.max_hz).toFixed(2)} Hz` : "—";
      $("t2Excursion").textContent = `${summary.longest_excursion_ms ?? 0} ms`;
      $("t2Alarms").textContent    = summary.alarm_events ?? 0;
    }
    if (status === "completed" || status === "completed_with_warnings" || status === "failed" || status === "aborted") {
      $("t2Start").disabled = false;
      $("t2Abort").disabled = true;
    }
  });
}

async function _onT2Abort() {
  const id = $("t2RunId")?.textContent;
  if (!id || id === "—") return;
  await _abortComplianceRun(id);
}

function refreshComplianceT2Status() { /* reserved — runs are watched via interval */ }

function buildComplianceT3Pane() {
  const pane = document.createElement("div");
  pane.className = "plant-cap-tab-pane";
  pane.dataset.tab = "t3";
  pane.id = "plantCapTabPaneT3";
  // Default sweep mirrors server/compliance/testT3.js DEFAULT_PF_SWEEP — short
  // operator-readable form is encoded as comma-sep PF entries with sign suffix.
  // Format: "1.00,0.99lag,0.98lag,...,1.00,0.99lead,...,1.00".
  pane.innerHTML = `
    <div class="cmp-panel">
      <div class="cmp-panel-head">
        <div>
          <div class="cmp-panel-title">Test T3 — Reactive Power / Q-V Capability <span class="cmp-badge" id="t3FlagBadge">Read-only</span></div>
          <div class="cmp-panel-sub">Automated PF sweep (cmd 1 — tan φ) per PGC 2016 GCR 4.4.4.1: 1.00 → 0.95 lag → 1.00 → 0.95 lead → 1.00. Per-step capture of P/Q/V and PF deviation. Reactive control is restored (cmd 11) on completion or abort. Writes require <code>gridControlEnabled = "1"</code>.</div>
        </div>
      </div>

      <details class="cmp-howto" data-cmp-howto="t3">
        <summary class="cmp-howto-title">How this test works</summary>
        <ol class="cmp-howto-steps">
          <li><b>Pick the node</b> and confirm <b>Sweep</b> (PF list + sign), <b>Hold</b> seconds, <b>Tolerance</b>.</li>
          <li><b>Press Run sweep.</b> The gateway writes phi-tangent setpoints (cmd 1) per step, holds each plateau for the configured time, then averages observed PF.</li>
          <li><b>Watch the Live observation panel.</b> cosφ + Q (kVAR) tick every 3 s as the inverter responds to each new setpoint.</li>
          <li><b>On completion or abort</b>, reactive control is restored to default (cmd 11). Status <i>completed_with_warnings</i> means the restore write failed — verify on the Read-back panel.</li>
        </ol>
        <div class="cmp-howto-note">Writes are blocked unless <code>gridControlEnabled = "1"</code>. Use <b>Read-back state</b> below to query holding 41006-41010 — that path is always safe.</div>
      </details>

      ${_complianceTargetSelectorMarkup("t3")}
      <div class="cmp-target-row">
        <label class="cmp-label" for="t3Sweep" title="Comma-separated PF list with sign. Defaults to the full 21-step NGCP sweep 1.00 → 0.95 lag → 1.00 → 0.95 lead → 1.00.">Sweep</label>
        <input id="t3Sweep" type="text" value="1.00,0.99,0.98,0.97,0.96,0.95,0.96,0.97,0.98,0.99,1.00,-0.99,-0.98,-0.97,-0.96,-0.95,-0.96,-0.97,-0.98,-0.99,1.00" class="cmp-text cmp-text-flex" />
        <label class="cmp-label" for="t3Hold">Hold (s/step)</label>
        <input id="t3Hold" type="number" min="20" max="900" step="10" value="60" class="cmp-num" />
        <label class="cmp-label" for="t3Settle">Settle (s)</label>
        <input id="t3Settle" type="number" min="5" max="120" step="5" value="15" class="cmp-num" />
        <label class="cmp-label" for="t3Tol" title="Allowed deviation between observed PF and target PF, in percentage points. Default 5 % per θ-3 acceptance criterion.">Tol (±%)</label>
        <input id="t3Tol" type="number" min="1" max="20" step="0.5" value="5" class="cmp-num" />
      </div>
      <div class="cmp-target-help">
        <b>PF sign convention:</b>
        <span style="color:var(--green);">0.95 = lag</span> (inductive, Q&nbsp;&gt;&nbsp;0 — inverter <i>injects</i> reactive power),
        <span style="color:var(--orange);">-0.95 = lead</span> (capacitive, Q&nbsp;&lt;&nbsp;0 — inverter <i>absorbs</i> reactive power),
        <b>1.00</b> = unity (Q&nbsp;=&nbsp;0). Use a leading <b>minus sign</b> only for lead; positive is implied otherwise.
        PDF cmd 1 absolute limit is ±0.90; NGCP PGC 4.4.4.1 envelope is ±0.95. Range allowed per step: 0.90–1.00.
      </div>
      <div class="cmp-actions">
        <button id="t3Start" class="btn btn-accent btn-xs" type="button" disabled title="Disabled until gridControlEnabled = &quot;1&quot; (Slice ζ hardware-soak gate).">Run sweep</button>
        <button id="t3Abort" class="btn btn-xs" type="button" disabled>Abort</button>
        <button id="t3Readback" class="btn btn-xs" type="button" title="Read holding 41006-41010 (always safe).">Read-back state</button>
        <span class="cmp-status" id="t3Status">Idle.</span>
      </div>
      <div class="cmp-progress" id="t3ProgressWrap" hidden>
        <div class="cmp-progress-bar"><div class="cmp-progress-fill" id="t3ProgressFill"></div></div>
        <div class="cmp-progress-meta">
          <span id="t3ProgressElapsed">0:00 elapsed</span>
          <span id="t3ProgressRemaining">— remaining</span>
          <span id="t3ProgressLastTick">—</span>
        </div>
      </div>
      <div class="cmp-results">
        <div class="cmp-result-row"><span>Run ID</span><b id="t3RunId">—</b></div>
        <div class="cmp-result-row"><span>Steps pass / fail</span><b id="t3StepResult">—</b></div>
        <div class="cmp-result-row"><span>Last observed PF</span><b id="t3LastObserved">—</b></div>
      </div>
      <div class="cmp-step-log" id="t3StepLog"></div>

      <div class="cmp-live-feed">
        <div class="cmp-live-feed-head">
          <span class="cmp-live-feed-title">Live observation feed</span>
          <span class="cmp-live-feed-sub" id="t3LiveSub">Last 20 samples — refreshes every 3 s</span>
        </div>
        <div class="cmp-live-feed-table-wrap">
          <table class="cmp-live-feed-table">
            <thead>
              <tr><th>Time</th><th>cosφ</th><th>Q (kVAR)</th><th>State</th><th>Alarm bits</th><th>P (kW)</th></tr>
            </thead>
            <tbody id="t3LiveFeedBody">
              <tr class="cmp-live-feed-empty"><td colspan="6">No samples yet. Press Run sweep.</td></tr>
            </tbody>
          </table>
        </div>
      </div>

      <div class="apc-history-section">
        <div class="apc-history-head" tabindex="0">
          <span class="apc-history-title">Live read-back (holding 41006-41010)</span>
        </div>
        <div id="t3ReadbackWrap" class="apc-history-wrap" style="padding:10px 14px;font-family:var(--font-mono);font-size:11px;color:var(--text2);">
          <em>Click <b>Read-back state</b> to query the inverter's current grid-control registers.</em>
        </div>
      </div>
    </div>`;
  setTimeout(() => {
    $("t3Start")?.addEventListener("click", _onT3Start);
    $("t3Abort")?.addEventListener("click", _onT3Abort);
    $("t3Readback")?.addEventListener("click", _onT3ReadbackClick);
    refreshComplianceT3Readback(); // sync feature-flag badge + button-disabled state on first build
  }, 0);
  return pane;
}

// Updates the T3 panel's feature-flag badge + Run button state.
async function refreshComplianceT3Readback() {
  try {
    const r = await fetch("/api/grid-control/feature-status");
    const data = await r.json();
    const enabled = !!data?.enabled;
    const badge = $("t3FlagBadge");
    const startBtn = $("t3Start");
    if (badge) {
      badge.textContent = enabled ? "Writes enabled" : "Read-only";
      badge.className = "cmp-badge " + (enabled ? "cmp-badge-green" : "cmp-badge-amber");
    }
    if (startBtn) startBtn.disabled = !enabled;
  } catch (_) { /* soft */ }
}

function _parseT3Sweep(str) {
  // Accepts signed-PF tokens. Convention: "+0.95"/"0.95" = lag, "-0.95" = lead,
  // "1.00" = unity (sign ignored). PF magnitude must be 0.90 ≤ |pf| ≤ 1.00.
  // Legacy "0.99lag"/"0.99lead" suffix form still parses for backward compat.
  return String(str || "")
    .split(",")
    .map(s => s.trim().toLowerCase())
    .filter(Boolean)
    .map(token => {
      // Legacy suffix form first.
      if (token.endsWith("lag") || token.endsWith("lead")) {
        const sign = token.endsWith("lag") ? "lag" : "lead";
        const pf = Number(token.replace(/(lag|lead)$/, ""));
        if (!Number.isFinite(pf) || pf < 0.90 || pf > 1.00) return null;
        return { pf, sign };
      }
      // Signed form. Note `Number("+0.95")` and `Number("-0.95")` both work.
      const num = Number(token);
      if (!Number.isFinite(num)) return null;
      const mag = Math.abs(num);
      if (mag < 0.90 || mag > 1.00) return null;
      // Unity: sign carries no meaning.
      if (mag >= 0.9999) return { pf: 1.00, sign: "0" };
      const sign = num < 0 ? "lead" : "lag";
      return { pf: mag, sign };
    })
    .filter(Boolean);
}

async function _onT3ReadbackClick() {
  const target = _readComplianceTarget("t3");
  const wrap = $("t3ReadbackWrap");
  if (!target || !wrap) {
    if (wrap) wrap.innerHTML = '<em style="color:var(--orange);">Pick an inverter # / slave first.</em>';
    return;
  }
  wrap.innerHTML = '<em>Reading…</em>';
  try {
    const r = await fetch(`/api/grid-control/state/${encodeURIComponent(target.ip)}/${target.slave}`);
    const data = await r.json();
    if (!r.ok || !data.ok) {
      wrap.innerHTML = `<em style="color:var(--red);">Read failed: ${escapeHtml(data?.error || `HTTP ${r.status}`)}</em>`;
      return;
    }
    wrap.innerHTML = `
      <div><b>41006 Power-reduction Q15:</b> ${data.power_q15} → ${Number(data.power_pct_readback || 0).toFixed(1)} %</div>
      <div><b>41007 Phi tangent (raw Int16):</b> ${data.phi_tangent_signed} → tan(φ) ${Number(data.phi_tangent_value || 0).toFixed(4)} → PF ≈ ${Number(data.power_factor_estimate || 0).toFixed(3)}</div>
      <div><b>41008 Reactive setpoint:</b> ${data.reactive_signed} (raw, ×10 = VAr) → ${Number(data.reactive_kvar || 0).toFixed(2)} kVAr</div>
      <div><b>41010 Restrictive freq limits:</b> ${data.freq_limits_on ? "ON (49.5/50.5 Hz CEI 0-21 — DO NOT issue cmd 12 on this site)" : "OFF (firmware Country Code 42 envelope active)"}</div>`;
  } catch (err) {
    wrap.innerHTML = `<em style="color:var(--red);">Network error: ${escapeHtml(err.message)}</em>`;
  }
}

async function _onT3Start() {
  const setStatus = (msg) => { const el = $("t3Status"); if (el) el.textContent = msg; };
  const target = _readComplianceTarget("t3");
  if (!target) {
    const inv = $("t3Inv")?.value || "?";
    const ipMap = State?.ipConfig?.inverters || {};
    const ipForInv = ipMap[Number(inv)] || ipMap[String(inv)] || "(none)";
    setStatus(`✗ No IP for inverter #${inv} — IP Config has "${ipForInv}". Fix the IP Config or type the IP manually.`);
    showToast("Pick a valid inverter # / slave.", "warn", 3000);
    return;
  }
  const sweep = _parseT3Sweep($("t3Sweep")?.value);
  if (sweep.length < 2) {
    setStatus("✗ Sweep needs ≥ 2 PF steps (e.g. \"1.00,0.95,1.00\" — minus sign for lead).");
    showToast("Sweep must contain at least 2 PF steps (e.g. \"1.00,0.95lag,1.00\").", "warn", 4000);
    return;
  }
  // Use the in-app appConfirm modal (consistent with the rest of the dashboard).
  // window.confirm still works in Electron but renders as a native OS dialog
  // — visually jarring next to the dark-themed in-app modals.
  const proceed = await appConfirm(
    "Start T3 Q-V sweep?",
    `Inverter ${target.inverter} slave ${target.slave}.\n\n` +
    `${sweep.length} PF steps × ${$("t3Hold")?.value || 60}s/step ≈ ${Math.round(sweep.length * (Number($("t3Hold")?.value) || 60) / 60)} min.\n\n` +
    `Reactive control will be restored (cmd 11) on completion or abort.`,
    { ok: "Run sweep", cancel: "Cancel" },
  );
  if (!proceed) { setStatus("Cancelled."); return; }
  const authKey = await _bulkAuthForCompliance("Start T3 Q-V sweep on", `inverter ${target.inverter} slave ${target.slave}`);
  if (!authKey) {
    setStatus("✗ Cancelled — bulk-control authorization required.");
    showToast("Cancelled.", "warn", 1500);
    return;
  }
  const body = {
    test_kind: "t3_qv_sweep",
    targets: [target], operator: "operator", authKey,
    params: {
      pf_steps: sweep,
      hold_sec:      Number($("t3Hold")?.value)   || 60,
      settle_sec:    Number($("t3Settle")?.value) || 15,
      tolerance_pct: Number($("t3Tol")?.value)    || 5,
      sample_period_s: 2,
    },
  };
  setStatus("Starting…");
  const resp = await fetch("/api/compliance/run/start", {
    method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(body),
  }).catch(e => ({ ok: false, status: 0, _err: e.message }));
  if (resp.status === 403) clearBulkAuthCache();
  const r = resp.json ? await resp.json().catch(() => ({ ok: false, error: resp._err || "parse error" })) : resp;
  if (!r.ok) {
    setStatus(`✗ Start failed: ${r.error || "unknown error"}`);
    showToast(r.error || "Start failed.", "err", 5000);
    return;
  }
  const t3StartedAt = Date.now();
  const t3DurationSec = sweep.length * (Number($("t3Hold")?.value) || 60);
  $("t3RunId").textContent = r.run_id;
  $("t3Status").textContent = "Running — driving phi-tangent setpoints…";
  $("t3Start").disabled = true;
  $("t3Abort").disabled = false;
  $("t3StepLog").innerHTML = "";
  $("t3LiveFeedBody").innerHTML = `<tr class="cmp-live-feed-empty"><td colspan="6">Waiting for first sample…</td></tr>`;
  _watchComplianceRun(r.run_id, (status, summary, steps, live) => {
    const tail = (live?.samples_tail) || [];
    const sampleTotal = live?.sample_count_total ?? 0;
    const lastSampleTs = tail.length > 0 ? Number(tail[tail.length - 1].ts_ms) : null;
    if (status === "running") {
      $("t3Status").textContent = sampleTotal > 0
        ? `Running — step ${(steps?.length || 0)}/${sweep.length}, ${sampleTotal} samples`
        : "Running — waiting for first frame…";
    } else {
      $("t3Status").textContent = status;
    }
    _updateComplianceProgress("t3", t3StartedAt, t3DurationSec, sampleTotal, lastSampleTs);
    _renderComplianceLiveFeed("t3LiveFeedBody", tail, "t3");
    if (summary) {
      $("t3StepResult").textContent = `${summary.passes ?? 0} / ${(summary.passes ?? 0) + (summary.fails ?? 0)}`;
    }
    // Live PF — derived from cosphi or P+Q on the most recent samples.
    // Lets operator see the inverter responding to phi_tangent writes
    // instead of staring at a blank "Last observed" until step end.
    if (status === "running" && tail.length > 0) {
      const pfs = tail.map(s => {
        const cp = Number(s.cosphi);
        if (Number.isFinite(cp) && Math.abs(cp) >= 0.5 && Math.abs(cp) <= 1.0) return Math.abs(cp);
        const p = Number(s.pac_w), q = Number(s.qac_var);
        if (Number.isFinite(p) && Number.isFinite(q)) {
          const sApp = Math.sqrt(p * p + q * q);
          if (sApp >= 1) return Math.abs(p) / sApp;
        }
        return null;
      }).filter(v => v != null);
      if (pfs.length > 0) {
        const mean = pfs.reduce((a, b) => a + b, 0) / pfs.length;
        $("t3LastObserved").textContent = "PF ≈ " + mean.toFixed(3) + ` (live, n=${live.sample_count_total})`;
      }
    }
    if (steps && steps.length) {
      const last = steps[steps.length - 1];
      if (last?.achieved_value != null) {
        $("t3LastObserved").textContent = "PF ≈ " + Number(last.achieved_value).toFixed(3);
      }
      const log = $("t3StepLog");
      if (log) {
        log.innerHTML = steps.map(s => `
          <div class="cmp-step-row ${s.pass === 1 ? "ok" : (s.pass === 0 ? "fail" : "")}">
            <span>${s.step_idx}. ${s.step_name}</span>
            <span>target PF ${s.target_value != null ? Number(s.target_value).toFixed(2) : "—"}</span>
            <span>observed ${s.achieved_value != null ? Number(s.achieved_value).toFixed(3) : "—"}</span>
            <span>dev ${s.deviation_pct != null ? Number(s.deviation_pct).toFixed(2) + " pp" : "—"}</span>
            <span>${s.pass == null ? "…" : (s.pass ? "PASS" : "FAIL")}</span>
          </div>`).join("");
      }
    }
    if (status === "completed" || status === "completed_with_warnings" || status === "failed" || status === "aborted") {
      $("t3Start").disabled = !GridControlUI?.enabled;
      $("t3Abort").disabled = true;
    }
  });
}

async function _onT3Abort() {
  const id = $("t3RunId")?.textContent;
  if (!id || id === "—") return;
  await _abortComplianceRun(id);
}

function buildComplianceT5Pane() {
  const pane = document.createElement("div");
  pane.className = "plant-cap-tab-pane";
  pane.dataset.tab = "t5";
  pane.id = "plantCapTabPaneT5";
  pane.innerHTML = `
    <div class="cmp-panel">
      <div class="cmp-panel-head">
        <div>
          <div class="cmp-panel-title">Test T5 — Active Power Control Sweep</div>
          <div class="cmp-panel-sub">Drives the configured ramp via cmd-3 setpoint writes, holds each plateau, and records observed PAC vs target. Pass per node = steady-state error ≤ ±2 % of target. Inverter is restored to 100 % on completion or abort.</div>
        </div>
      </div>

      <details class="cmp-howto" data-cmp-howto="t5">
        <summary class="cmp-howto-title">How this test works</summary>
        <ol class="cmp-howto-steps">
          <li><b>Pick the node</b>, then enter <b>Ramp</b> (% setpoints comma-sep), <b>Hold</b> seconds per step, and tolerance.</li>
          <li><b>Press Run sweep.</b> Each step writes a new %P setpoint (cmd 3 → holding 41006), waits the settle window, then averages observed PAC over the remainder of the hold.</li>
          <li><b>Watch the Live observation panel.</b> P (kW) and Iac (A) tick every 3 s — operator sees the inverter ramp track the setpoint mid-hold instead of waiting for step end.</li>
          <li><b>On completion or abort</b>, the runner writes 100 % to every target so the plant is never left curtailed. Status <i>completed_with_warnings</i> means that restore failed — verify on the APC tab.</li>
        </ol>
        <div class="cmp-howto-note">PAC tracks setpoint with a 30 s settle window per the NGCP §2.5 acceptance criterion. Steady-state error must be within ±tolerance %.</div>
      </details>

      ${_complianceTargetSelectorMarkup("t5")}
      <div class="cmp-target-row">
        <label class="cmp-label" for="t5Ramp">Ramp (% comma-sep)</label>
        <input id="t5Ramp" type="text" value="100,75,50,25,75,100" class="cmp-text cmp-text-flex" />
        <label class="cmp-label" for="t5Hold">Hold (s/step)</label>
        <input id="t5Hold" type="number" min="30" max="900" step="10" value="120" class="cmp-num" />
        <label class="cmp-label" for="t5Settle">Settle (s)</label>
        <input id="t5Settle" type="number" min="5" max="120" step="5" value="30" class="cmp-num" />
        <label class="cmp-label" for="t5Tol">Tol (±%)</label>
        <input id="t5Tol" type="number" min="0.5" max="10" step="0.1" value="2" class="cmp-num" />
      </div>
      <div class="cmp-actions">
        <button id="t5Start" class="btn btn-accent btn-xs" type="button">Run sweep</button>
        <button id="t5Abort" class="btn btn-xs" type="button" disabled>Abort</button>
        <span class="cmp-status" id="t5Status">Idle.</span>
      </div>
      <div class="cmp-progress" id="t5ProgressWrap" hidden>
        <div class="cmp-progress-bar"><div class="cmp-progress-fill" id="t5ProgressFill"></div></div>
        <div class="cmp-progress-meta">
          <span id="t5ProgressElapsed">0:00 elapsed</span>
          <span id="t5ProgressRemaining">— remaining</span>
          <span id="t5ProgressLastTick">—</span>
        </div>
      </div>
      <div class="cmp-results">
        <div class="cmp-result-row"><span>Run ID</span><b id="t5RunId">—</b></div>
        <div class="cmp-result-row"><span>Steps pass / fail</span><b id="t5StepResult">—</b></div>
        <div class="cmp-result-row"><span>Last achieved %</span><b id="t5LastAchieved">—</b></div>
      </div>
      <div class="cmp-step-log" id="t5StepLog"></div>

      <div class="cmp-live-feed">
        <div class="cmp-live-feed-head">
          <span class="cmp-live-feed-title">Live observation feed</span>
          <span class="cmp-live-feed-sub" id="t5LiveSub">Last 20 samples — refreshes every 3 s</span>
        </div>
        <div class="cmp-live-feed-table-wrap">
          <table class="cmp-live-feed-table">
            <thead>
              <tr><th>Time</th><th>P (kW)</th><th>—</th><th>State</th><th>Alarm bits</th><th>Iac avg</th></tr>
            </thead>
            <tbody id="t5LiveFeedBody">
              <tr class="cmp-live-feed-empty"><td colspan="6">No samples yet. Press Run sweep.</td></tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>`;
  setTimeout(() => {
    $("t5Start")?.addEventListener("click", _onT5Start);
    $("t5Abort")?.addEventListener("click", _onT5Abort);
  }, 0);
  return pane;
}

async function _onT5Start() {
  const setStatus = (msg) => { const el = $("t5Status"); if (el) el.textContent = msg; };
  const target = _readComplianceTarget("t5");
  if (!target) {
    const inv = $("t5Inv")?.value || "?";
    const ipMap = State?.ipConfig?.inverters || {};
    const ipForInv = ipMap[Number(inv)] || ipMap[String(inv)] || "(none)";
    setStatus(`✗ No IP for inverter #${inv} — IP Config has "${ipForInv}". Fix the IP Config or type the IP manually.`);
    showToast("Pick a valid inverter # / slave.", 3000);
    return;
  }
  const rampStr = String($("t5Ramp")?.value || "");
  const ramp = rampStr.split(",").map(s => Number(s.trim())).filter(n => Number.isFinite(n) && n >= 0 && n <= 100);
  if (ramp.length < 2) {
    setStatus("✗ Ramp needs ≥ 2 setpoints (e.g. \"100,75,50,75,100\").");
    showToast("Ramp must contain at least 2 setpoints.", 3000);
    return;
  }
  const authKey = await _bulkAuthForCompliance("Start T5 APC sweep on", `inverter ${target.inverter} slave ${target.slave}`);
  if (!authKey) {
    setStatus("✗ Cancelled — bulk-control authorization required.");
    showToast("Cancelled.", 1500);
    return;
  }
  const body = {
    test_kind: "t5_apc_sweep",
    targets: [target], operator: "operator", authKey,
    params: {
      ramp_pct: ramp,
      hold_sec:      Number($("t5Hold")?.value)   || 120,
      settle_sec:    Number($("t5Settle")?.value) || 30,
      tolerance_pct: Number($("t5Tol")?.value)    || 2,
      sample_period_s: 2,
    },
  };
  setStatus("Starting…");
  const resp = await fetch("/api/compliance/run/start", {
    method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(body),
  }).catch(e => ({ ok: false, status: 0, _err: e.message }));
  if (resp.status === 403) clearBulkAuthCache();
  const r = resp.json ? await resp.json().catch(() => ({ ok: false, error: resp._err || "parse error" })) : resp;
  if (!r.ok) {
    setStatus(`✗ Start failed: ${r.error || "unknown error"}`);
    showToast(r.error || "Start failed.", 4000);
    return;
  }
  const t5StartedAt = Date.now();
  const t5DurationSec = ramp.length * (Number($("t5Hold")?.value) || 120);
  $("t5RunId").textContent = r.run_id;
  $("t5Status").textContent = "Running — driving setpoint ramp…";
  $("t5Start").disabled = true;
  $("t5Abort").disabled = false;
  $("t5StepLog").innerHTML = "";
  $("t5LiveFeedBody").innerHTML = `<tr class="cmp-live-feed-empty"><td colspan="6">Waiting for first sample…</td></tr>`;
  _watchComplianceRun(r.run_id, (status, summary, steps, live) => {
    const tail = (live?.samples_tail) || [];
    const sampleTotal = live?.sample_count_total ?? 0;
    const lastSampleTs = tail.length > 0 ? Number(tail[tail.length - 1].ts_ms) : null;
    if (status === "running") {
      $("t5Status").textContent = sampleTotal > 0
        ? `Running — step ${(steps?.length || 0)}/${ramp.length}, ${sampleTotal} samples`
        : "Running — waiting for first frame…";
    } else {
      $("t5Status").textContent = status;
    }
    _updateComplianceProgress("t5", t5StartedAt, t5DurationSec, sampleTotal, lastSampleTs);
    _renderComplianceLiveFeed("t5LiveFeedBody", tail, "t5");
    if (summary) {
      $("t5StepResult").textContent = `${summary.passes ?? 0} / ${(summary.passes ?? 0) + (summary.fails ?? 0)}`;
    }
    // Live achieved-% — mean of pac_w in the recent tail relative to rated
    // 244.25 kW per node. Lets operator confirm the setpoint took effect
    // mid-hold instead of waiting for endStep() to compute the final value.
    if (status === "running" && tail.length > 0) {
      const watts = tail.map(s => Number(s.pac_w)).filter(v => Number.isFinite(v));
      if (watts.length > 0) {
        const meanW = watts.reduce((a, b) => a + b, 0) / watts.length;
        const ratedW = 244.25 * 1000 * (target ? 1 : 0);
        if (ratedW > 0) {
          const pct = (meanW / ratedW) * 100;
          $("t5LastAchieved").textContent = pct.toFixed(2) + ` % (live, n=${live.sample_count_total})`;
        }
      }
    }
    if (steps && steps.length) {
      const last = steps[steps.length - 1];
      if (last?.achieved_value != null) $("t5LastAchieved").textContent = Number(last.achieved_value).toFixed(2) + " %";
      const log = $("t5StepLog");
      if (log) {
        log.innerHTML = steps.map(s => `
          <div class="cmp-step-row ${s.pass === 1 ? "ok" : (s.pass === 0 ? "fail" : "")}">
            <span>${s.step_idx}. ${s.step_name}</span>
            <span>target ${s.target_value ?? "—"} %</span>
            <span>achieved ${s.achieved_value != null ? Number(s.achieved_value).toFixed(2) + " %" : "—"}</span>
            <span>dev ${s.deviation_pct != null ? Number(s.deviation_pct).toFixed(2) + " %" : "—"}</span>
            <span>${s.pass == null ? "…" : (s.pass ? "PASS" : "FAIL")}</span>
          </div>`).join("");
      }
    }
    if (status === "completed" || status === "completed_with_warnings" || status === "failed" || status === "aborted") {
      $("t5Start").disabled = false;
      $("t5Abort").disabled = true;
    }
  });
}

async function _onT5Abort() {
  const id = $("t5RunId")?.textContent;
  if (!id || id === "—") return;
  await _abortComplianceRun(id);
}

function refreshComplianceT5Status() { /* reserved */ }

function buildComplianceReportsPane() {
  const pane = document.createElement("div");
  pane.className = "plant-cap-tab-pane";
  pane.dataset.tab = "reports";
  pane.id = "plantCapTabPaneReports";
  pane.innerHTML = `
    <div class="cmp-panel">
      <div class="cmp-panel-head">
        <div>
          <div class="cmp-panel-title">Compliance Reports</div>
          <div class="cmp-panel-sub">Past test runs. <b>Excel</b> = three-sheet workbook (Run Info / Steps / Samples), styled and ready to print. <b>PDF</b> = printable witness report (takes a few seconds).</div>
        </div>
        <button id="cmpReportsRefresh" class="btn btn-xs" type="button" title="Refresh the run history from the database.">↻ Refresh</button>
      </div>
      <table class="cmp-runs-table">
        <thead>
          <tr><th>Started</th><th>Test</th><th>Status</th><th>Operator</th><th>Run ID</th><th class="cmp-actions-col">Export</th></tr>
        </thead>
        <tbody id="cmpRunsBody"><tr><td colspan="6" class="cmp-empty">Loading…</td></tr></tbody>
      </table>
    </div>`;
  setTimeout(() => {
    $("cmpReportsRefresh")?.addEventListener("click", refreshComplianceReports);
  }, 0);
  return pane;
}

// Friendly labels for the Test column so operators don't read raw enum values.
const _CMP_TEST_LABELS = {
  t2_freq_withstand: "T2 Freq Withstand",
  t3_qv_sweep:       "T3 Q-V Sweep",
  t5_apc_sweep:      "T5 APC Sweep",
};

async function refreshComplianceReports() {
  const r = await fetch("/api/compliance/runs?limit=50").then(r => r.json()).catch(e => ({ ok: false, error: e.message }));
  const body = $("cmpRunsBody");
  if (!body) return;
  if (!r.ok) { body.innerHTML = `<tr><td colspan="6" class="cmp-empty">${r.error || "Load failed."}</td></tr>`; return; }
  if (!r.runs || r.runs.length === 0) {
    body.innerHTML = `<tr><td colspan="6" class="cmp-empty">No runs yet. Start one from the T2 / T3 / T5 tab.</td></tr>`;
    return;
  }
  body.innerHTML = r.runs.map(run => {
    const testLbl = _CMP_TEST_LABELS[run.test_kind] || run.test_kind;
    // PDF only available for runs that ended (completed / completed_with_warnings / failed / aborted).
    const isTerminal = run.status && run.status !== "running";
    const pdfTitle = isTerminal ? "Download PDF only" : "Available after the run finishes.";
    const pdfDis = isTerminal ? "" : " disabled";
    return `
      <tr data-run-id="${run.run_id}">
        <td>${new Date(run.started_at_ms).toLocaleString()}</td>
        <td>${testLbl}</td>
        <td class="cmp-status-cell cmp-status-${run.status}">${run.status}</td>
        <td>${run.operator_actor || "—"}</td>
        <td><code class="cmp-runid">${run.run_id}</code></td>
        <td class="cmp-actions-col">
          <button class="btn btn-xs cmp-xlsx" data-run-id="${run.run_id}" title="Download styled Excel workbook (3 sheets, autofit columns, centered cells).">Excel</button>
          <button class="btn btn-xs cmp-pdf" data-run-id="${run.run_id}" title="${pdfTitle}"${pdfDis}>PDF</button>
        </td>
      </tr>`;
  }).join("");
  // v2.11.x — Excel button replaces the legacy CSV button. CSV is messy in
  // Excel (single sheet, no styling, "section" column noise) — XLSX gives
  // the three-sheet workbook operators expect for witness handover. CSV is
  // still reachable via the API for external scripts.
  body.querySelectorAll(".cmp-xlsx").forEach(b => b.addEventListener("click", () => _onComplianceReportClick(b.dataset.runId, "xlsx")));
  // PDF button passes "pdf" (was "both") so the user gets only the PDF
  // artifact instead of CSV+PDF on every PDF click.
  body.querySelectorAll(".cmp-pdf").forEach(b => b.addEventListener("click", () => _onComplianceReportClick(b.dataset.runId, "pdf")));
}

async function _onComplianceReportClick(runId, format) {
  // Both endpoints (POST /report to generate, GET /artifact to download)
  // are gated by isAuthorizedPlantWideControl — without authKey/authToken
  // the server returns 403 "Unauthorized." Run the same auth flow as every
  // other privileged action so the operator sees the confirm + (optional)
  // auth modal once per hour.
  const kindLabel = format === "both" ? "PDF + CSV"
                  : format === "pdf"  ? "PDF"
                  : format === "xlsx" ? "Excel"
                  : "CSV";
  const authKey = await _bulkAuthForCompliance(`Generate ${kindLabel} report for`, `run ${String(runId).slice(0, 16)}`);
  if (!authKey) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  const resp = await fetch(`/api/compliance/run/${encodeURIComponent(runId)}/report`, {
    method: "POST", headers: { "content-type": "application/json" },
    body: JSON.stringify({ format, authKey, operator: "operator" }),
  }).catch(e => ({ ok: false, status: 0, _err: e.message }));
  if (resp.status === 403) clearBulkAuthCache();
  const r = resp.json ? await resp.json().catch(() => ({ ok: false, error: resp._err || "parse error" })) : resp;
  if (!r.ok) { showToast(r.error || "Report failed.", 4000); return; }
  // Auto-download the artifact(s). The GET endpoint accepts authKey as a
  // query-string param so we can use a plain <a href> without an XHR.
  for (const a of (r.artifacts || [])) {
    if (a.error) { showToast(`${a.kind}: ${a.error}`, 4000); continue; }
    const url = `/api/compliance/run/${encodeURIComponent(runId)}/artifact`
              + `?kind=${encodeURIComponent(a.kind)}`
              + `&authKey=${encodeURIComponent(authKey)}`;
    const link = document.createElement("a");
    link.href = url;
    link.download = "";
    document.body.appendChild(link);
    link.click();
    link.remove();
  }
}

function _watchComplianceRun(runId, onUpdate) {
  if (_compliancePollers[runId]) clearInterval(_compliancePollers[runId]);
  const tick = async () => {
    try {
      const r = await fetch(`/api/compliance/run/${encodeURIComponent(runId)}/status?tail=20`).then(r => r.json());
      if (!r.ok) return;
      const status = r.run?.status || r.live_status || "running";
      let summary = null;
      try { summary = r.run?.summary_json ? JSON.parse(r.run.summary_json) : null; } catch (_) {}
      // v2.11.x — pass live observation context to per-test watchers so the
      // operator sees telemetry flowing during a 30-min run instead of staring
      // at "Running…" with no progress signal until finalize() fires.
      const live = {
        sample_count_pending_flush: Number(r.sample_count_pending_flush || 0),
        sample_count_persisted:     Number(r.sample_count_persisted || 0),
        sample_count_total:         Number(r.sample_count_total || 0),
        sample_dropped:             Number(r.sample_dropped || 0),
        samples_tail:               Array.isArray(r.samples_tail) ? r.samples_tail : [],
      };
      onUpdate(status, summary, r.steps || [], live);
      if (status === "completed" || status === "completed_with_warnings" || status === "failed" || status === "aborted") {
        clearInterval(_compliancePollers[runId]);
        delete _compliancePollers[runId];
      }
    } catch (_) { /* soft */ }
  };
  _compliancePollers[runId] = setInterval(tick, 3000);
  tick();
}

async function _abortComplianceRun(runId) {
  const authKey = await _bulkAuthForCompliance("Abort", `compliance run ${runId}`);
  if (!authKey) return;
  await fetch(`/api/compliance/run/${encodeURIComponent(runId)}/abort`, {
    method: "POST", headers: { "content-type": "application/json" },
    body: JSON.stringify({ authKey, operator: "operator" }),
  }).catch(() => {});
}

function renderApcPane() {
  const status = State.plantCap.status || {};
  const mwActive = status.enabled && status.status !== "idle" && status.status !== "fault";
  const banner = $("apcLockoutBanner");
  if (banner) banner.hidden = !mwActive;
  const applyBtn = $("apcApplyBtn");
  const stopBtn = $("apcStopBtn");
  const startBtn = $("apcStartBtn");
  if (applyBtn) applyBtn.disabled = mwActive;
  if (stopBtn) stopBtn.disabled = mwActive;
  if (startBtn) startBtn.disabled = mwActive;
  const job = State.apc.activeJob;
  const progressWrap = $("apcProgressWrap");
  const fill = $("apcProgressFill");
  const label = $("apcProgressLabel");
  const abortBtn = $("apcAbortBtn");
  if (progressWrap) {
    const running = job && job.status === "running";
    progressWrap.hidden = !running;
    if (abortBtn) abortBtn.hidden = !running;
    if (running) {
      const pct = Math.round((job.steps_done || 0) / Math.max(job.steps_total || 1, 1) * 100);
      if (fill) fill.style.width = pct + "%";
      if (label) label.textContent = `${pct}% — step ${job.steps_done || 0}/${job.steps_total || 0}`;
    }
  }
  updateApcNodeCurrentPct();
}

async function fetchApcState() {
  try {
    const r = await fetch("/api/plant-cap/setpoint/state");
    if (!r.ok) return;
    const data = await r.json();
    if (data.ok && Array.isArray(data.states)) {
      const map = {};
      data.states.forEach((s) => { map[`${s.ip}:${s.slave}`] = s; });
      State.apc.state = map;
    }
  } catch (_) {}
  // Slice δ — pull the per-node verify history alongside the setpoint state.
  fetchApcVerifyStatus();
  updateApcNodeCurrentPct();
}

// Lightweight 30 s poll while the %P Setpoint tab is visible. Without it, the
// Current pill goes stale whenever a setpoint changes from another operator,
// a scheduler tick, or the auto-curtailment loop.
let _apcStatePollTimer = null;
function _startApcStatePoll() {
  if (_apcStatePollTimer) return;
  _apcStatePollTimer = setInterval(() => {
    if (State.plantCapActiveTab === "apc") fetchApcState();
  }, 30_000);
}
function _stopApcStatePoll() {
  if (_apcStatePollTimer) {
    clearInterval(_apcStatePollTimer);
    _apcStatePollTimer = null;
  }
}

async function fetchApcHistory() {
  const tbody = $("apcHistoryBody");
  if (!tbody) return;
  try {
    const r = await fetch("/api/plant-cap/history?limit=20");
    if (!r.ok) return;
    const data = await r.json();
    const rows = (data.history || []).filter((row) => row.scope && row.scope.startsWith("apc:"));
    renderApcHistory(rows);
  } catch (_) {}
}

function renderApcHistory(rows) {
  const tbody = $("apcHistoryBody");
  if (!tbody) return;
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:var(--text2);padding:10px;">No history yet.</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map((row) => {
    const ts = row.ts ? new Date(row.ts).toLocaleString() : "—";
    const scope = row.scope || "—";
    const action = row.action || "—";
    const detail = [row.ip, row.node != null ? `node ${row.node}` : "", row.reason].filter(Boolean).join(" · ");
    const badgeCls = action === "apc_set" ? "apc-badge apc-badge-set"
      : action === "apc_stop" ? "apc-badge apc-badge-stop"
      : action === "apc_start" ? "apc-badge apc-badge-start"
      : action === "apc_abort" ? "apc-badge apc-badge-err"
      : row.result === "ok" ? "apc-badge apc-badge-ok"
      : "apc-badge apc-badge-err";
    return `<tr>
      <td>${ts}</td>
      <td>${scope}</td>
      <td><span class="${badgeCls}">${action}</span></td>
      <td style="font-size:0.78rem;color:var(--text2)">${detail}</td>
    </tr>`;
  }).join("");
}

async function submitApcApply() {
  const scopeEl = document.querySelector('input[name="apcScope"]:checked');
  const scope = scopeEl ? scopeEl.value : "node";
  const ipSel = $("apcIpSel");
  const nodeSel = $("apcNodeSel");
  const pctInp = $("apcPctInp");
  let target_pct = pctInp ? Number(pctInp.value) : 100;
  if (!Number.isFinite(target_pct)) target_pct = 100;
  target_pct = Math.max(0, Math.min(100, Math.round(target_pct)));
  let targets = [];
  if (scope === "node") {
    const inv = Number(ipSel?.value);
    const slave = Number(nodeSel?.value);
    const ip = getConfiguredInverterIp(inv);
    if (!ip || !slave) { showToast("Select a valid inverter and node first.", "warn"); return; }
    targets = [{ ip, slave }];
  } else if (scope === "inverter") {
    const inv = Number(ipSel?.value);
    const ip = getConfiguredInverterIp(inv);
    if (!ip) { showToast("Select a valid inverter first.", "warn"); return; }
    const units = getConfiguredUnits(inv, 4);
    targets = units.map((u) => ({ ip, slave: u }));
  } else if (scope === "plant") {
    const invMap = State.ipConfig?.inverters || {};
    const invNums = Object.keys(invMap).map(Number).filter((n) => n > 0 && invMap[n]).sort((a, b) => a - b);
    if (!invNums.length) { showToast("No inverters configured.", "warn"); return; }
    for (const n of invNums) {
      const ip = invMap[n] || invMap[String(n)] || "";
      if (!ip) continue;
      getConfiguredUnits(n, 4).forEach((u) => targets.push({ ip, slave: u }));
    }
    if (target_pct < 5) {
      const ok = await appConfirm(
        "Very low plant setpoint",
        `Setting the entire plant to ${target_pct} % will curtail almost all generation. Continue?`,
        { ok: `Apply ${target_pct}%`, cancel: "Cancel" },
      );
      if (!ok) return;
    }
  }
  // Auth modal — same flow as compliance/MW Cap. Cached for the session
  // after first use, so subsequent Applies skip the prompt automatically.
  const auth = await _bulkAuthForCompliance(
    `Apply ${target_pct}% setpoint to`,
    scope === "plant" ? "the entire plant" : `${targets.length} target node(s)`,
  );
  if (!auth) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  const btn = $("apcApplyBtn");
  if (btn) btn.disabled = true;
  try {
    const r = await fetch("/api/plant-cap/setpoint/apply", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ scope, targets, target_pct, authKey: auth }),
    });
    const data = await r.json();
    if (r.status === 403) {
      clearBulkAuthCache();
      showToast(data.error || "Authorization expired — please re-enter the authorization key next click.", "warning", 5000);
    } else if (r.status === 409) {
      showToast(data.error || "MW Cap sequencer is active — release it first on the MW Cap tab.", "warn", 6000);
    } else if (!r.ok || !data.ok) {
      showToast(data.error || "Apply failed.", "err", 6000);
    } else {
      State.apc.activeJob = { job_id: data.job_id, status: "running", steps_done: 0, steps_total: data.steps_total || 1 };
      renderApcPane();
      showToast(`Ramp started (job ${String(data.job_id || "").slice(0, 8)}).`, "ok", 4000);
      _apcStartJobPoll(data.job_id);
    }
  } catch (e) {
    showToast("Network error: " + e.message, "err");
  } finally {
    const b = $("apcApplyBtn");
    if (b) b.disabled = false;
  }
}

async function submitApcOp(opcode) {
  const scopeEl = document.querySelector('input[name="apcScope"]:checked');
  const scope = scopeEl ? scopeEl.value : "node";
  const ipSel = $("apcIpSel");
  const nodeSel = $("apcNodeSel");
  const inv = Number(ipSel?.value);
  const ip = getConfiguredInverterIp(inv);
  let targets = [];
  if (scope === "plant") {
    const invMap = State.ipConfig?.inverters || {};
    const invNums = Object.keys(invMap).map(Number).filter((n) => n > 0 && invMap[n]).sort((a, b) => a - b);
    if (!invNums.length) { showToast("No inverters configured.", "warn"); return; }
    for (const n of invNums) {
      const plantIp = invMap[n] || invMap[String(n)] || "";
      if (!plantIp) continue;
      getConfiguredUnits(n, 4).forEach((u) => targets.push({ ip: plantIp, slave: u }));
    }
    if (opcode === "stop") {
      // window.prompt() is silently disabled in Electron (returns null) — every
      // plant-wide STOP would be auto-cancelled if we used it. Route the
      // safety phrase through the in-app appPrompt modal instead. The check
      // is case-sensitive and trims whitespace so a stray space doesn't
      // green-light the action.
      const phrase = await appPrompt(
        "Confirm plant-wide STOP",
        'Type "STOP ALL INVERTERS" exactly to confirm. This stops every configured node.',
        { placeholder: "STOP ALL INVERTERS" },
      );
      if (String(phrase || "").trim() !== "STOP ALL INVERTERS") {
        showToast("Plant-wide STOP cancelled.", "warn");
        return;
      }
    }
  } else if (scope === "inverter") {
    if (!ip) { showToast("Select a valid inverter first.", "warn"); return; }
    targets = getConfiguredUnits(inv, 4).map((u) => ({ ip, slave: u }));
  } else {
    const slave = Number(nodeSel?.value);
    if (!ip || !slave) { showToast("Select a valid inverter and node first.", "warn"); return; }
    targets = [{ ip, slave }];
  }
  if (opcode === "start") {
    const stateMap = State.apc?.state || {};
    const missing = targets.filter((t) => {
      const rec = stateMap[`${t.ip}:${t.slave}`];
      return !rec || rec.active_pct == null;
    });
    if (missing.length > 0) {
      const preview = missing.slice(0, 3).map((m) => `${m.ip}/${m.slave}`).join(", ");
      const more = missing.length > 3 ? ` +${missing.length - 3} more` : "";
      showToast(
        `Cannot START — ${missing.length} target(s) have no prior %P setpoint (${preview}${more}). ` +
        `Apply Setpoint first.`,
        "warn",
        7000,
      );
      return;
    }
  }
  const opLabel = opcode === "stop" ? "STOP" : "START";
  const auth = await _bulkAuthForCompliance(
    `${opLabel} on`,
    scope === "plant" ? "the entire plant" : `${targets.length} target node(s)`,
  );
  if (!auth) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  const btn = opcode === "stop" ? $("apcStopBtn") : $("apcStartBtn");
  if (btn) btn.disabled = true;
  try {
    const r = await fetch("/api/plant-cap/setpoint/apply", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ scope, targets, target_pct: null, opcode, authKey: auth }),
    });
    const data = await r.json();
    if (r.status === 403) {
      clearBulkAuthCache();
      showToast(data.error || "Authorization expired — please re-enter the authorization key next click.", "warning", 5000);
    } else if (r.status === 409 && data?.reason === "no_prior_setpoint") {
      showToast(data.error || "START blocked: no prior %P setpoint.", "warn", 7000);
    } else if (!r.ok || !data.ok) {
      showToast(data.error || `${opcode} failed.`, "err", 6000);
    } else {
      showToast(`${opcode === "stop" ? "STOP" : "START"} sent.`, "ok", 4000);
      setTimeout(() => fetchApcState(), 800);
    }
  } catch (e) {
    showToast("Network error: " + e.message, "err");
  } finally {
    if (btn) btn.disabled = false;
  }
}

async function submitApcAbort(jobId) {
  const auth = await _bulkAuthForCompliance("Abort %P ramp", `job ${String(jobId || "").slice(0, 8)}`);
  if (!auth) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  try {
    const r = await fetch(`/api/plant-cap/setpoint/abort/${jobId}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ authKey: auth }),
    });
    const data = await r.json();
    if (r.status === 403) {
      clearBulkAuthCache();
      showToast(data.error || "Authorization expired — please re-enter the authorization key next click.", "warning", 5000);
    } else if (!r.ok || !data.ok) {
      showToast(data.error || "Abort failed.", "err");
    } else {
      showToast("Ramp aborted.", "warn", 4000);
      State.apc.activeJob = null;
      renderApcPane();
    }
  } catch (e) {
    showToast("Network error: " + e.message, "err");
  }
}

function _apcStartJobPoll(jobId) {
  if (State.apc.jobPollTimer) clearInterval(State.apc.jobPollTimer);
  State.apc.jobPollTimer = setInterval(async () => {
    try {
      const r = await fetch(`/api/plant-cap/setpoint/jobs/${jobId}`);
      if (!r.ok) return;
      const data = await r.json();
      if (data.ok && data.job) {
        State.apc.activeJob = data.job;
        renderApcPane();
        if (data.job.status !== "running") {
          clearInterval(State.apc.jobPollTimer);
          State.apc.jobPollTimer = null;
          if (data.job.status === "done") {
            showToast("Ramp complete.", "ok", 4000);
            fetchApcState();
            fetchApcHistory();
          } else if (data.job.status === "aborted") {
            showToast("Ramp aborted.", "warn", 4000);
          } else if (data.job.status === "error") {
            showToast("Ramp error: " + (data.job.error || "unknown"), "err", 8000);
          }
        }
      }
    } catch (_) {}
  }, 1500);
}

function _apcSyncScopeUi() {
  const scopeEl = document.querySelector('input[name="apcScope"]:checked');
  const scope = scopeEl ? scopeEl.value : "node";
  const ipSel = $("apcIpSel");
  const nodeSel = $("apcNodeSel");
  const nodeCurrent = $("apcNodeCurrent");
  const nodesInfo = $("apcNodesInfo");
  const plantInfo = $("apcPlantInfo");
  const isPlant = scope === "plant";
  const isInverter = scope === "inverter";
  if (ipSel) ipSel.hidden = isPlant;
  if (nodeSel) nodeSel.hidden = isInverter || isPlant;
  if (nodeCurrent) nodeCurrent.hidden = isInverter || isPlant;
  if (nodesInfo) {
    nodesInfo.hidden = !isInverter;
    if (isInverter && ipSel) {
      const inv = Number(ipSel.value);
      const units = inv > 0 ? getConfiguredUnits(inv, 4) : [];
      nodesInfo.textContent = units.length ? `Nodes: ${units.join(", ")}` : "—";
    }
  }
  if (plantInfo) {
    plantInfo.hidden = !isPlant;
    if (isPlant) {
      const invMap = State.ipConfig?.inverters || {};
      const invNums = Object.keys(invMap).map(Number).filter((n) => n > 0 && invMap[n]).sort((a, b) => a - b);
      const totalNodes = invNums.reduce((s, n) => s + getConfiguredUnits(n, 4).length, 0);
      plantInfo.textContent = `${invNums.length} inverters, ${totalNodes} nodes`;
    }
  }
}

function buildApcPane() {
  const pane = document.createElement("div");
  pane.className = "plant-cap-tab-pane";
  pane.dataset.tab = "apc";
  pane.id = "plantCapTabPaneApc";
  pane.innerHTML = `
    <div class="apc-panel">
      <div class="apc-panel-head">
        <div class="apc-panel-title">Active Power Setpoint</div>
        <div class="apc-panel-subtitle">Continuous %P (Q15) curtailment via Modbus FC16 → register 0x03E8</div>
      </div>

      <div id="apcLockoutBanner" class="apc-lockout-banner" hidden>
        <span class="mdi mdi-alert-circle-outline" aria-hidden="true"></span>
        <span>MW Cap sequencer is active.&nbsp;<button class="apc-tab-link" type="button" id="apcToMwCapLink">Go to MW Cap</button>&nbsp;and release control first.</span>
      </div>

      <div class="apc-form-grid">
        <div class="apc-field">
          <label class="apc-field-lbl">Scope</label>
          <div class="apc-scope-row">
            <label class="apc-chip-radio" title="Apply to a single inverter node.">
              <input type="radio" name="apcScope" value="node" checked><span>Per Node</span>
            </label>
            <label class="apc-chip-radio" title="Apply to all nodes on one inverter IP.">
              <input type="radio" name="apcScope" value="inverter"><span>Per Inverter</span>
            </label>
            <label class="apc-chip-radio" title="Apply to every node across all configured inverters. Requires bulk-control authorization.">
              <input type="radio" name="apcScope" value="plant"><span>Plant-Wide</span>
            </label>
          </div>
        </div>

        <div class="apc-field">
          <label class="apc-field-lbl">Target</label>
          <div class="apc-target-row">
            <select id="apcIpSel" class="sel" title="Inverter (1–27). Each is one INGECON SUN unit at a fixed IP."></select>
            <select id="apcNodeSel" class="sel" title="Internal node (1–4) — independent power converter inside the inverter, addressed by its Modbus slave ID. There is NO fixed master node; the master role rotates dynamically every cycle, so each converter must be commanded individually."></select>
            <span class="apc-current-pill" title="Current active power setpoint for this internal node">
              <span class="apc-current-pill-lbl">Current</span>
              <span id="apcNodeCurrent">—</span>
            </span>
            <span id="apcNodesInfo" class="apc-info-pill" hidden title="All internal nodes (slaves) under this inverter will receive the command"></span>
            <span id="apcPlantInfo" class="apc-info-pill" hidden title="All configured nodes plant-wide — requires bulk-control authorization"></span>
          </div>
          <small class="apc-field-help">
            <b>Inverter</b> = one INGECON SUN unit (27 total). <b>Internal node</b> = a Modbus slave (1–4) inside the inverter — each is an independent IGBT converter with its own DC sub-array. The inverter has no fixed master; the leader role rotates per cycle, which is why active-power commands target nodes individually.
          </small>
        </div>

        <div class="apc-field">
          <label class="apc-field-lbl" for="apcPctInp">Setpoint</label>
          <div class="apc-setpoint-row">
            <div class="apc-pct-input">
              <input id="apcPctInp" class="inp" type="number" min="0" max="100" step="1" value="100"
                title="Active power setpoint as a percentage of rated capacity (0–100)">
              <span class="apc-pct-suffix">%</span>
            </div>
            <div class="apc-presets">
              <button class="btn btn-outline btn-sm apc-preset-btn" type="button" data-pct="100" title="Full output">100</button>
              <button class="btn btn-outline btn-sm apc-preset-btn" type="button" data-pct="90">90</button>
              <button class="btn btn-outline btn-sm apc-preset-btn" type="button" data-pct="75">75</button>
              <button class="btn btn-outline btn-sm apc-preset-btn" type="button" data-pct="50">50</button>
              <button class="btn btn-outline btn-sm apc-preset-btn" type="button" data-pct="25">25</button>
              <button class="btn btn-outline btn-sm apc-preset-btn" type="button" data-pct="0" title="Lowest setpoint (verify lower bound on the inverter)">0</button>
            </div>
          </div>
        </div>

        <div class="apc-field apc-field-auth-note">
          <span class="apc-field-lbl">Authorization</span>
          <span class="apc-auth-note">
            Click STOP / START / Apply Setpoint and you'll be prompted for the
            bulk-control authorization key. Same modal as the rest of the
            dashboard; cached for the session after the first use.
          </span>
        </div>
      </div>

      <div class="apc-actions">
        <button id="apcStopBtn" class="btn btn-red" type="button"
          title="Halt active-power injection on the selected target (Modbus opcode 0x0005). The inverter stays grid-synced and online — only the power output goes to 0%. Requires bulk-control authorization.">
          <span class="mdi mdi-stop-circle-outline" aria-hidden="true"></span><span>STOP</span>
        </button>
        <button id="apcStartBtn" class="btn btn-green" type="button"
          title="Resume active-power injection (Modbus opcode 0x0006) at the previously written %P setpoint. A prior Apply Setpoint is required — START alone has nothing to resume to.">
          <span class="mdi mdi-play-circle-outline" aria-hidden="true"></span><span>START</span>
        </button>
        <span class="apc-actions-divider" aria-hidden="true"></span>
        <button id="apcApplyBtn" class="btn btn-accent" type="button"
          title="Write a new active-power setpoint (Modbus opcode 0x0003) and ramp toward it. This is the only command that changes the %P level; STOP/START just gate output at the level Apply set.">
          <span class="mdi mdi-flash" aria-hidden="true"></span><span>Apply Setpoint</span>
        </button>
      </div>
      <div class="apc-actions-help" aria-hidden="false">
        <span class="item stop"><span class="swatch"></span><b>STOP</b> — halt active-power output on this node. Inverter stays grid-synced; only the kW injection goes to 0%. Use to pause output without disconnecting.</span>
        <span class="item start"><span class="swatch"></span><b>START</b> — resume output at the previously-written %P. Requires a prior Apply Setpoint, otherwise the inverter has nothing to resume to (request is rejected).</span>
        <span class="item apply"><span class="swatch"></span><b>Apply Setpoint</b> — write the active-power %P level (0–100) and ramp toward it. STOP/START only gate the output; this is what actually changes how much power flows.</span>
      </div>

      <!-- v2.11.x Phase 2 — APC ramp-rate limiter (inline, Plant Controller page) -->
      <div class="apc-ramp-row" id="apcRampRow"
           title="Soft ramp pacer. When enabled, every Apply Setpoint write that would change %P faster than the configured rate is split into 15-second steps that converge on the target. NGCP PGC §4.4.4.6 reference; off by default.">
        <label class="apc-ramp-toggle">
          <input type="checkbox" id="apcRampRateEnabledInline">
          <span><b>Ramp-rate limiter</b></span>
        </label>
        <label class="apc-ramp-rate">
          <span>Max ramp</span>
          <input type="number" id="apcRampRatePctPerMinInline" class="inp inp-sm" min="1" max="100" step="1" value="10">
          <span class="apc-ramp-suffix">%/min</span>
        </label>
        <span id="apcRampStatus" class="apc-ramp-status" aria-live="polite"></span>
      </div>

      <div id="apcProgressWrap" class="apc-progress-wrap" hidden>
        <div class="apc-progress-bar"><div id="apcProgressFill" class="apc-progress-fill" style="width:0%"></div></div>
        <span id="apcProgressLabel" class="apc-progress-label"></span>
        <button id="apcAbortBtn" class="btn btn-outline btn-sm apc-abort-btn" type="button" hidden>Abort</button>
      </div>

      <div class="apc-history-section">
        <div class="apc-history-head" id="apcHistoryHead" role="button" tabindex="0" title="Toggle APC action history">
          <span class="apc-history-title">History</span>
          <span id="apcHistoryChevron" class="apc-history-chevron">▼</span>
        </div>
        <div id="apcHistoryWrap" class="apc-history-wrap" hidden>
          <table class="apc-history-table">
            <thead><tr><th>Time</th><th>Scope</th><th>Action</th><th>Detail</th></tr></thead>
            <tbody id="apcHistoryBody"></tbody>
          </table>
        </div>
      </div>
    </div>`;

  const pctInp = pane.querySelector("#apcPctInp");
  const clampPct = () => {
    if (!pctInp) return;
    let v = Number(pctInp.value);
    if (!Number.isFinite(v)) v = 100;
    if (v < 0) v = 0;
    if (v > 100) v = 100;
    pctInp.value = String(Math.round(v));
  };
  if (pctInp) {
    pctInp.addEventListener("change", clampPct);
    pctInp.addEventListener("blur", clampPct);
  }
  pane.querySelectorAll(".apc-preset-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      if (pctInp) pctInp.value = btn.dataset.pct;
    });
  });
  const ipSel = pane.querySelector("#apcIpSel");
  if (ipSel) ipSel.addEventListener("change", () => { updateApcNodeSlaveOptions(); _apcSyncScopeUi(); });
  const nodeSel = pane.querySelector("#apcNodeSel");
  if (nodeSel) nodeSel.addEventListener("change", updateApcNodeCurrentPct);
  pane.querySelectorAll('input[name="apcScope"]').forEach((r) => {
    r.addEventListener("change", _apcSyncScopeUi);
  });
  const stopBtn = pane.querySelector("#apcStopBtn");
  if (stopBtn) stopBtn.addEventListener("click", () => submitApcOp("stop"));
  const startBtn = pane.querySelector("#apcStartBtn");
  if (startBtn) startBtn.addEventListener("click", () => submitApcOp("start"));
  const applyBtn = pane.querySelector("#apcApplyBtn");
  if (applyBtn) applyBtn.addEventListener("click", submitApcApply);
  const abortBtn = pane.querySelector("#apcAbortBtn");
  if (abortBtn) abortBtn.addEventListener("click", () => {
    if (State.apc.activeJob?.job_id) submitApcAbort(State.apc.activeJob.job_id);
  });
  const histHead = pane.querySelector("#apcHistoryHead");
  const histWrap = pane.querySelector("#apcHistoryWrap");
  const histChevron = pane.querySelector("#apcHistoryChevron");
  if (histHead && histWrap) {
    histHead.addEventListener("click", () => {
      histWrap.hidden = !histWrap.hidden;
      if (histChevron) histChevron.classList.toggle("open", !histWrap.hidden);
      if (!histWrap.hidden) fetchApcHistory();
    });
    histHead.addEventListener("keydown", (e) => { if (e.key === "Enter" || e.key === " ") histHead.click(); });
  }
  const toMwCapLink = pane.querySelector("#apcToMwCapLink");
  if (toMwCapLink) toMwCapLink.addEventListener("click", () => switchPlantCapTab("mw-cap"));
  // v2.11.x Phase 2 — ramp limiter inline controls. Persist via /api/settings
  // (same backing store as before; we just moved the UI surface).
  const rampToggle = pane.querySelector("#apcRampRateEnabledInline");
  const rampInput  = pane.querySelector("#apcRampRatePctPerMinInline");
  const rampStatus = pane.querySelector("#apcRampStatus");
  function _setRampStatus(text, kind) {
    if (!rampStatus) return;
    rampStatus.textContent = text || "";
    rampStatus.className = "apc-ramp-status" + (kind ? " " + kind : "");
  }
  async function _saveRampSettings() {
    const enabled = rampToggle?.checked ? "1" : "0";
    const raw = Number(rampInput?.value);
    const rate = Number.isFinite(raw) && raw >= 1 && raw <= 100 ? String(Math.trunc(raw)) : "10";
    if (rampInput) rampInput.value = rate;
    _setRampStatus("Saving…", "pending");
    try {
      const r = await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          apcRampRateEnabled: enabled,
          apcRampRatePctPerMin: rate,
        }),
      });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      _setRampStatus(enabled === "1" ? `Pacing @ ${rate}%/min` : "Disabled (immediate writes)", enabled === "1" ? "on" : "off");
      State.settings = State.settings || {};
      State.settings.apcRampRateEnabled = enabled;
      State.settings.apcRampRatePctPerMin = rate;
    } catch (err) {
      _setRampStatus(`Save failed: ${err.message}`, "err");
    }
  }
  if (rampToggle) rampToggle.addEventListener("change", _saveRampSettings);
  if (rampInput)  rampInput.addEventListener("change", _saveRampSettings);
  // Initial hydrate from State.settings (which loadSettings populated at startup).
  (function _hydrateRampUI() {
    const enabled = String(State.settings?.apcRampRateEnabled ?? "0") === "1";
    const rate = (() => {
      const n = Number(State.settings?.apcRampRatePctPerMin);
      return Number.isFinite(n) && n >= 1 && n <= 100 ? Math.trunc(n) : 10;
    })();
    if (rampToggle) rampToggle.checked = enabled;
    if (rampInput)  rampInput.value = String(rate);
    _setRampStatus(enabled ? `Pacing @ ${rate}%/min` : "Disabled (immediate writes)", enabled ? "on" : "off");
  })();
  return pane;
}

// ─── end APC ────────────────────────────────────────────────────────────────

/* ────────────────────────────────────────────────────────────────────────
 * Slice ζ — Grid Code (reactive power + power-factor) UI tab
 * Plan: plans/2026-05-10-modbus-registers-official-revamp.md §4 Slice ζ
 * Reference card: docs/Inverter-Modbus-Reference.md §6 (cmd 1 / 9 / 11)
 *
 * SAFETY POSTURE:
 *   - Default: writes are disabled (server-side gridControlEnabled = "0").
 *   - The pane shows a hard banner explaining what's required to enable.
 *   - Read-back panel works regardless of flag — visibility never harms.
 *   - All write controls are disabled when feature-status reports !enabled.
 * ──────────────────────────────────────────────────────────────────────── */

const GridControlUI = {
  enabled: false,    // mirror of server's `gridControlEnabled` setting
  state: null,       // last read-back result
  inverter: null,
  slave: null,
};

function buildGridControlPane() {
  const pane = document.createElement("div");
  pane.className = "plant-cap-tab-pane";
  pane.dataset.tab = "grid-control";
  pane.id = "plantCapTabPaneGridControl";
  pane.innerHTML = `
    <div class="cmp-panel">
      <div class="cmp-panel-head">
        <div class="cmp-panel-title">Grid Code — Reactive Power &amp; Power Factor <span class="cmp-badge cmp-badge-amber" id="gcFeatureBadge">Read-only</span></div>
        <div class="cmp-panel-subtitle">Modbus FC16 commands 1 (tan φ) / 9 (kVAr) / 11 (disable) + holding read-back 41006-41010.</div>
      </div>

      <div id="gcSafetyBanner" class="apc-lockout-banner">
        <span class="mdi mdi-alert-circle-outline" aria-hidden="true"></span>
        <span><b>Writes are DISABLED.</b> Enabling requires (1) security review, (2) 2-week single-inverter soak, (3) operator sign-off, and (4) <code>gridControlEnabled = "1"</code> in settings. Read-back works regardless. See <a href="user-guide.html#s6" target="_blank">User Guide → Plant Cap</a>.</span>
      </div>

      <div class="apc-form-grid">
        <div class="apc-field">
          <label class="apc-field-lbl">Target</label>
          <div class="apc-target-row">
            <select id="gcIpSel" class="sel" title="Inverter (1–27)."></select>
            <select id="gcNodeSel" class="sel" title="Internal node (1–4) — Modbus slave inside the inverter."></select>
            <button id="gcReadBackBtn" class="btn btn-outline btn-sm" type="button" title="Read holding registers 41006-41010 (always safe).">
              <span class="mdi mdi-refresh" aria-hidden="true"></span><span>Read state</span>
            </button>
          </div>
        </div>

        <div class="apc-field">
          <label class="apc-field-lbl">PF target</label>
          <div class="apc-setpoint-row">
            <div class="apc-pct-input">
              <input id="gcPfInp" class="inp" type="number" min="0.90" max="1.00" step="0.01" value="1.00"
                     title="Power factor target. NGCP requires 0.95 lag/lead; PDF cmd 1 absolute limit is 0.90.">
              <span class="apc-pct-suffix">PF</span>
            </div>
            <div class="apc-presets">
              <button class="btn btn-outline btn-sm" type="button" data-pf="0.95" data-sign="lag" title="0.95 lagging (NGCP boundary, inductive)">0.95 lag</button>
              <button class="btn btn-outline btn-sm" type="button" data-pf="1.00" data-sign="0" title="Unity">1.00</button>
              <button class="btn btn-outline btn-sm" type="button" data-pf="0.95" data-sign="lead" title="0.95 leading (NGCP boundary, capacitive)">0.95 lead</button>
            </div>
          </div>
        </div>

        <div class="apc-field">
          <label class="apc-field-lbl">Reactive (kVAr)</label>
          <div class="apc-setpoint-row">
            <div class="apc-pct-input">
              <input id="gcKvarInp" class="inp" type="number" step="0.1" value="0"
                     title="Direct reactive power setpoint in kVAr (positive = lag/inject, negative = lead/absorb). Range bounded by inverter nominal kVA.">
              <span class="apc-pct-suffix">kVAr</span>
            </div>
          </div>
        </div>

        <div class="apc-field apc-field-auth-note">
          <span class="apc-field-lbl">Authorization</span>
          <span class="apc-auth-note">
            Click <b>Set PF</b> / <b>Set kVAr</b> / <b>Disable reactive</b> and you'll be prompted for the
            bulk-control authorization key. Same modal as the rest of the
            dashboard; cached for the session after the first use.
          </span>
        </div>
      </div>

      <div class="apc-actions">
        <button id="gcSetPfBtn" class="btn btn-accent" type="button" disabled
                title="Cmd 1 — write tan(φ) target derived from PF (and sign).">
          <span class="mdi mdi-sine-wave" aria-hidden="true"></span><span>Set PF</span>
        </button>
        <button id="gcSetReactiveBtn" class="btn btn-accent" type="button" disabled
                title="Cmd 9 — write reactive power setpoint. Wire raw = kVAr × 100 (raw × 10 = VAr per PDF).">
          <span class="mdi mdi-flash-triangle" aria-hidden="true"></span><span>Set kVAr</span>
        </button>
        <span class="apc-actions-divider" aria-hidden="true"></span>
        <button id="gcDisableBtn" class="btn btn-red" type="button" disabled
                title="Cmd 11 — disable reactive reference, restore inverter default.">
          <span class="mdi mdi-restore" aria-hidden="true"></span><span>Disable reactive</span>
        </button>
      </div>
      <div class="apc-actions-help" aria-hidden="false">
        <span class="item apply"><span class="swatch"></span><b>Set PF</b> — write tan(φ) derived from the PF input. NGCP min 0.95 lag/lead; PDF absolute limit 0.90.</span>
        <span class="item apply"><span class="swatch"></span><b>Set kVAr</b> — direct reactive setpoint. Positive = lagging (inject reactive), negative = leading (absorb).</span>
        <span class="item stop"><span class="swatch"></span><b>Disable reactive</b> — release the inverter back to its default PF behavior. Always-safe restore.</span>
      </div>

      <div class="apc-history-section">
        <div class="apc-history-head" tabindex="0">
          <span class="apc-history-title">Read-back state (holding 41006-41010)</span>
        </div>
        <div id="gcStateWrap" class="apc-history-wrap" style="padding:10px 14px;font-family:var(--font-mono);font-size:11px;color:var(--text2);">
          <em>Click <b>Read state</b> to query the inverter's current grid-control registers.</em>
        </div>
      </div>
    </div>

    <!-- v2.11.x Phase 1 — Grid Monitor (rolling 5-min × 5-sec visibility) -->
    <!-- Plan: plans/2026-05-12-ppc-capabilities-implementation.md §2 -->
    <div class="cmp-panel" id="gridMonitorPanel" style="margin-top:12px;">
      <div class="cmp-panel-head">
        <div class="cmp-panel-title">Grid Monitor <span class="cmp-badge cmp-badge-blue">Read-only</span></div>
        <div class="cmp-panel-subtitle">Rolling 5-min × 5-sec window of P, Q, frequency, voltage, ramp rate &amp; observed PF — sourced from live poller frames. NGCP compliance bands overlaid.</div>
      </div>
      <div id="gmChips" class="apc-chips-row" style="display:flex;gap:12px;flex-wrap:wrap;padding:8px 14px;font-family:var(--font-mono);font-size:11px;">
        <span class="cmp-badge cmp-badge-grey">Loading plant aggregate…</span>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(360px,1fr));gap:10px;padding:8px 14px 14px;">
        <div class="cmp-chart-card">
          <div class="cmp-chart-title">P vs f <span class="cmp-chart-hint">(NGCP 59.7–60.3 Hz continuous · 58.2–61.8 Hz withstand)</span></div>
          <canvas id="gmChartPf" height="180"></canvas>
        </div>
        <div class="cmp-chart-card">
          <div class="cmp-chart-title">Q vs V <span class="cmp-chart-hint">(±5% nominal band shaded)</span></div>
          <canvas id="gmChartQv" height="180"></canvas>
        </div>
        <div class="cmp-chart-card">
          <div class="cmp-chart-title">dP/dt — ramp rate <span class="cmp-chart-hint">(red line = configured APC ramp limit when enabled)</span></div>
          <canvas id="gmChartDp" height="180"></canvas>
        </div>
        <div class="cmp-chart-card">
          <div class="cmp-chart-title">Observed PF <span class="cmp-chart-hint">(NGCP 0.95 lag/lead boundaries)</span></div>
          <canvas id="gmChartPfTs" height="180"></canvas>
        </div>
      </div>
    </div>`;

  const ipSel = pane.querySelector("#gcIpSel");
  const nodeSel = pane.querySelector("#gcNodeSel");
  if (ipSel) ipSel.addEventListener("change", () => populateGridControlNodeOptions());
  if (nodeSel) nodeSel.addEventListener("change", () => { GridControlUI.slave = Number(nodeSel.value) || null; });

  pane.querySelectorAll("[data-pf]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const pfInp = pane.querySelector("#gcPfInp");
      if (pfInp) pfInp.value = btn.dataset.pf;
      pfInp?.setAttribute("data-sign", btn.dataset.sign || "0");
    });
  });

  pane.querySelector("#gcReadBackBtn")?.addEventListener("click", refreshGridControlReadback);
  pane.querySelector("#gcSetPfBtn")?.addEventListener("click", submitGridControlPf);
  pane.querySelector("#gcSetReactiveBtn")?.addEventListener("click", submitGridControlReactive);
  pane.querySelector("#gcDisableBtn")?.addEventListener("click", submitGridControlDisable);

  return pane;
}

function populateGridControlSelectors() {
  const sel = $("gcIpSel");
  if (!sel) return;
  const invMap = State.ipConfig?.inverters || {};
  const invNums = Object.keys(invMap).map(Number).filter((n) => n > 0 && invMap[n]).sort((a, b) => a - b);
  const prevVal = sel.value;
  sel.innerHTML = "";
  if (!invNums.length) {
    const opt = document.createElement("option");
    opt.value = "";
    opt.textContent = State.ipConfig ? "(no inverters configured)" : "(loading inverters…)";
    sel.appendChild(opt);
    return;
  }
  invNums.forEach((inv) => {
    const ip = invMap[inv] || invMap[String(inv)] || "";
    if (!ip) return;
    const opt = document.createElement("option");
    opt.value = String(inv);
    opt.textContent = `Inverter ${String(inv).padStart(2, "0")} — ${ip}`;
    sel.appendChild(opt);
  });
  if (prevVal && Array.from(sel.options).some((o) => o.value === prevVal)) sel.value = prevVal;
  populateGridControlNodeOptions();
}

function populateGridControlNodeOptions() {
  const ipSel = $("gcIpSel");
  const nodeSel = $("gcNodeSel");
  if (!ipSel || !nodeSel) return;
  const inv = Number(ipSel.value);
  const units = inv > 0 ? getConfiguredUnits(inv, 4) : [1, 2, 3, 4];
  const prevVal = nodeSel.value;
  nodeSel.innerHTML = "";
  units.forEach((u) => {
    const opt = document.createElement("option");
    opt.value = String(u);
    opt.textContent = `Internal node ${u} (slave ${u})`;
    nodeSel.appendChild(opt);
  });
  if (units.map(String).includes(prevVal)) nodeSel.value = prevVal;
  GridControlUI.slave = Number(nodeSel.value) || null;
}

async function refreshGridControlFeatureStatus() {
  try {
    const r = await fetch("/api/grid-control/feature-status");
    if (!r.ok) return;
    const data = await r.json();
    GridControlUI.enabled = !!data.enabled;
    const banner = $("gcSafetyBanner");
    const badge  = $("gcFeatureBadge");
    if (banner) banner.hidden = GridControlUI.enabled;
    if (badge) {
      badge.textContent = GridControlUI.enabled ? "Writes enabled" : "Read-only";
      badge.className = "cmp-badge " + (GridControlUI.enabled ? "cmp-badge-green" : "cmp-badge-amber");
    }
    ["gcSetPfBtn", "gcSetReactiveBtn", "gcDisableBtn"].forEach((id) => {
      const b = $(id); if (b) b.disabled = !GridControlUI.enabled;
    });
  } catch (_) {}
}

function _gcResolveTarget() {
  const inv = Number($("gcIpSel")?.value);
  const slave = Number($("gcNodeSel")?.value);
  const ip = getConfiguredInverterIp(inv);
  if (!ip || !slave) return null;
  return { ip, slave };
}

async function refreshGridControlReadback() {
  const t = _gcResolveTarget();
  const wrap = $("gcStateWrap");
  if (!t || !wrap) {
    if (wrap) wrap.innerHTML = '<em style="color:var(--orange);">Pick an inverter + node first.</em>';
    return;
  }
  wrap.innerHTML = '<em>Reading…</em>';
  try {
    const r = await fetch(`/api/grid-control/state/${encodeURIComponent(t.ip)}/${t.slave}`);
    const data = await r.json();
    if (!r.ok || !data.ok) {
      wrap.innerHTML = `<em style="color:var(--red);">Read failed: ${escapeHtml(data?.error || `HTTP ${r.status}`)}</em>`;
      return;
    }
    GridControlUI.state = data;
    wrap.innerHTML = `
      <div><b>Power-reduction Q15:</b> ${data.power_q15} → ${Number(data.power_pct_readback || 0).toFixed(1)} %</div>
      <div><b>Phi tangent (raw Int16):</b> ${data.phi_tangent_signed} → tan(φ) ${Number(data.phi_tangent_value || 0).toFixed(4)} → PF ≈ ${Number(data.power_factor_estimate || 0).toFixed(3)}</div>
      <div><b>Reactive setpoint:</b> ${data.reactive_signed} (raw, ×10 = VAr) → ${Number(data.reactive_kvar || 0).toFixed(2)} kVAr</div>
      <div><b>Restrictive freq limits flag:</b> ${data.freq_limits_on ? "ON (49.5/50.5 Hz CEI 0-21 — DO NOT issue cmd 12 on this site)" : "OFF (firmware Country Code 42 envelope active)"}</div>
      <div style="opacity:.6;margin-top:6px;">Raw regs 41006-41010: [${(data.regs || []).join(", ")}]</div>
      <div id="gcVerifyLine" style="margin-top:8px;"></div>`;
    // v2.11.x Phase 3 — surface last write verification.
    try {
      const vr = await fetch(`/api/grid-control/verify-status/${encodeURIComponent(t.ip)}/${t.slave}`, { cache: "no-store" });
      if (vr.ok) {
        const vd = await vr.json();
        const row = vd?.row;
        const line = document.getElementById("gcVerifyLine");
        if (line) {
          if (!row) {
            line.innerHTML = '<em style="opacity:.6;">No verification record yet.</em>';
          } else {
            const status = String(row.result || "?");
            const color =
              status === "ok" ? "var(--green)" :
              status === "mismatch" ? "var(--red)" :
              status === "pending" ? "var(--accent)" : "var(--orange)";
            const ageS = row.verify_ts_ms ? Math.round((Date.now() - row.verify_ts_ms) / 1000) : "—";
            line.innerHTML =
              `<b>Last verify:</b> <span style="color:${color};font-weight:600;">${escapeHtml(status.toUpperCase())}</span> ` +
              `(${escapeHtml(String(row.kind))} req=${row.requested_raw ?? "—"} obs=${row.observed_raw ?? "—"}; ` +
              `${ageS} s ago)`;
          }
        }
      }
    } catch (_) { /* verify-status optional */ }
  } catch (err) {
    wrap.innerHTML = `<em style="color:var(--red);">Network error: ${escapeHtml(err.message)}</em>`;
  }
}

function _pfToPhiRaw(pf, sign) {
  // tan(φ) = sqrt(1/PF² - 1) ; sign-from-input: "lag" → +, "lead" → -.
  const pfNum = Math.max(0.90, Math.min(1.00, Number(pf) || 1));
  const tanPhi = Math.sqrt(Math.max(0, 1 / (pfNum * pfNum) - 1));
  const signed = sign === "lead" ? -tanPhi : sign === "lag" ? tanPhi : 0;
  // PDF: phi_raw = tan(φ) × 32767 (NOT × 65535). NGCP PF 0.95 → ±10780 cross-check.
  return Math.round(signed * 32767);
}

async function submitGridControlPf() {
  if (!GridControlUI.enabled) return;
  const t = _gcResolveTarget();
  const pfInp = $("gcPfInp");
  if (!t) { showToast("Pick an inverter + node first.", "warn"); return; }
  const pf = Number(pfInp?.value);
  const sign = (pfInp?.getAttribute("data-sign") || "0");
  const phi_raw = _pfToPhiRaw(pf, sign);
  if (Math.abs(phi_raw) > 15870) { showToast("PF target exceeds PDF cmd 1 limit (PF < 0.90).", "warn"); return; }
  // Modal auth — same flow as APC. Cached per session after first use.
  const auth = await _bulkAuthForCompliance(`Set PF ${pf} ${sign} on`, `${t.ip}/${t.slave}`);
  if (!auth) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  const btn = $("gcSetPfBtn"); if (btn) btn.disabled = true;
  try {
    const r = await fetch("/api/grid-control/phi", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ip: t.ip, slave: t.slave, phi_raw, authKey: auth }),
    });
    const data = await r.json();
    if (r.status === 403) {
      clearBulkAuthCache();
      showToast(data.error || "Authorization expired — re-enter the key on the next click.", "warning", 5000);
    } else if (!r.ok || !data.ok) {
      showToast(data.error || `Set PF failed.`, "err", 6000);
    } else {
      showToast(`PF target sent (raw ${phi_raw}, ≈ PF ${pf} ${sign}).`, "ok", 4000);
      setTimeout(refreshGridControlReadback, 800);
    }
  } catch (e) {
    showToast("Network error: " + e.message, "err");
  } finally {
    if (btn) btn.disabled = !GridControlUI.enabled;
  }
}

async function submitGridControlReactive() {
  if (!GridControlUI.enabled) return;
  const t = _gcResolveTarget();
  if (!t) { showToast("Pick an inverter + node first.", "warn"); return; }
  const kvar = Number($("gcKvarInp")?.value);
  if (!Number.isFinite(kvar)) { showToast("kVAr value invalid.", "warn"); return; }
  // Wire convention (PDF §3 cmd 9): raw × 10 = VAr → raw = kVAr × 100.
  // The variable name `kvar_div10` is preserved for legacy callers but the
  // value is now correctly scaled. See audits/2026-05-11/register-decode-traceback.md
  // Finding 2 — earlier code used kvar*10 which under-wrote by 10×.
  const kvar_div10 = Math.round(kvar * 100);
  // Modal auth — same flow as APC. Cached per session after first use.
  const auth = await _bulkAuthForCompliance(`Set ${kvar.toFixed(1)} kVAr on`, `${t.ip}/${t.slave}`);
  if (!auth) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  const btn = $("gcSetReactiveBtn"); if (btn) btn.disabled = true;
  try {
    const r = await fetch("/api/grid-control/reactive", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ip: t.ip, slave: t.slave, kvar_div10, authKey: auth }),
    });
    const data = await r.json();
    if (r.status === 403) {
      clearBulkAuthCache();
      showToast(data.error || "Authorization expired — re-enter the key on the next click.", "warning", 5000);
    } else if (!r.ok || !data.ok) {
      showToast(data.error || `Set kVAr failed.`, "err", 6000);
    } else {
      showToast(`Reactive setpoint sent (${kvar.toFixed(1)} kVAr).`, "ok", 4000);
      setTimeout(refreshGridControlReadback, 800);
    }
  } catch (e) {
    showToast("Network error: " + e.message, "err");
  } finally {
    if (btn) btn.disabled = !GridControlUI.enabled;
  }
}

async function submitGridControlDisable() {
  if (!GridControlUI.enabled) return;
  const t = _gcResolveTarget();
  if (!t) { showToast("Pick an inverter + node first.", "warn"); return; }
  const ok = await appConfirm(
    "Disable reactive control?",
    `${t.ip} slave ${t.slave} — this restores the inverter's default PF behavior (cmd 11).`,
    { ok: "Disable reactive", cancel: "Cancel" },
  );
  if (!ok) return;
  // Modal auth — same flow as APC. Cached per session after first use.
  const auth = await _bulkAuthForCompliance(`Disable reactive control on`, `${t.ip}/${t.slave}`);
  if (!auth) {
    showToast("Cancelled — bulk-control authorization required.", "warning", 2500);
    return;
  }
  const btn = $("gcDisableBtn"); if (btn) btn.disabled = true;
  try {
    const r = await fetch("/api/grid-control/disable", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ip: t.ip, slave: t.slave, authKey: auth }),
    });
    const data = await r.json();
    if (r.status === 403) {
      clearBulkAuthCache();
      showToast(data.error || "Authorization expired — re-enter the key on the next click.", "warning", 5000);
    } else if (!r.ok || !data.ok) {
      showToast(data.error || `Disable failed.`, "err", 6000);
    } else {
      showToast("Reactive control disabled.", "ok", 4000);
      setTimeout(refreshGridControlReadback, 800);
    }
  } catch (e) {
    showToast("Network error: " + e.message, "err");
  } finally {
    if (btn) btn.disabled = !GridControlUI.enabled;
  }
}

// ─── v2.11.x Phase 1 — Grid Monitor rendering (charts + polling) ───────────
// Plan: plans/2026-05-12-ppc-capabilities-implementation.md §2
// All four charts share one polling loop. Pauses when the Grid Code tab isn't
// visible to avoid spinning Chart.js on a hidden canvas.
const GridMonitor = {
  charts: { pf: null, qv: null, dp: null, pfts: null },
  pollTimer: null,
  pollMs: 5000,
  // NGCP envelope (Philippine 60 Hz grid):
  bandFreqContinuous: [59.7, 60.3],
  bandFreqWithstand:  [58.2, 61.8],
  bandVoltPct: 5,           // ±% of nominal (default 480 V three-phase site)
  voltNominalV: 480,
  pfMin: 0.95,              // NGCP boundary
};

function _gmPaletteHash(key) {
  // Stable per-node colour. djb2-ish.
  let h = 5381;
  for (let i = 0; i < key.length; i++) h = ((h << 5) + h + key.charCodeAt(i)) | 0;
  const hue = Math.abs(h) % 360;
  return `hsl(${hue}, 70%, 55%)`;
}

function _gmEnsureChart(id, type, datasets, options) {
  const cvs = document.getElementById(id);
  if (!cvs || !window.Chart) return null;
  // Re-use the chart if it exists.
  if (GridMonitor.charts[id]) return GridMonitor.charts[id];
  const ctx = cvs.getContext("2d");
  const chart = new Chart(ctx, {
    type,
    data: { datasets },
    options,
  });
  GridMonitor.charts[id] = chart;
  return chart;
}

function _gmRenderScatterPf(nodes) {
  const datasets = nodes.map((n) => {
    const ip = n.inverter_ip;
    const slave = n.slave;
    const color = _gmPaletteHash(`${ip}#${slave}`);
    const points = (n.series || [])
      .filter((s) => s.freq_hz != null && s.pac_w != null)
      .map((s) => ({ x: s.freq_hz, y: s.pac_w / 1000 }));
    return {
      label: `${ip}/${slave}`,
      backgroundColor: color,
      borderColor: color,
      pointRadius: 2.5,
      data: points,
      showLine: false,
    };
  });
  const opts = {
    responsive: true,
    maintainAspectRatio: false,
    animation: false,
    parsing: false,
    plugins: {
      legend: { display: nodes.length <= 8, labels: { boxWidth: 8, font: { size: 10 } } },
      tooltip: { callbacks: {
        label: (ctx) => `${ctx.dataset.label}: ${ctx.parsed.x.toFixed(2)} Hz, ${ctx.parsed.y.toFixed(1)} kW`,
      } },
    },
    scales: {
      x: {
        type: "linear",
        min: 57.5, max: 62.0,
        title: { display: true, text: "Frequency (Hz)" },
        grid: { color: (ctx) => {
          const v = ctx.tick?.value;
          if (v == null) return "rgba(120,120,120,0.05)";
          // Continuous band edges in green, withstand in amber.
          if (v === 59.7 || v === 60.3) return "rgba(80,200,80,0.4)";
          if (v === 58.2 || v === 61.8) return "rgba(230,180,60,0.4)";
          return "rgba(120,120,120,0.08)";
        } },
      },
      y: {
        title: { display: true, text: "Active power P (kW)" },
        grid: { color: "rgba(120,120,120,0.08)" },
      },
    },
  };
  const chart = _gmEnsureChart("gmChartPf", "scatter", datasets, opts);
  if (chart) {
    chart.data.datasets = datasets;
    chart.update("none");
  }
}

function _gmRenderScatterQv(nodes) {
  const datasets = nodes.map((n) => {
    const ip = n.inverter_ip;
    const slave = n.slave;
    const color = _gmPaletteHash(`${ip}#${slave}`);
    const points = (n.series || [])
      .filter((s) => s.vac_avg_v != null && s.qac_var != null)
      .map((s) => ({ x: s.vac_avg_v, y: s.qac_var / 1000 }));
    return {
      label: `${ip}/${slave}`,
      backgroundColor: color,
      borderColor: color,
      pointRadius: 2.5,
      data: points,
      showLine: false,
    };
  });
  const vMin = GridMonitor.voltNominalV * (1 - 2 * GridMonitor.bandVoltPct / 100);
  const vMax = GridMonitor.voltNominalV * (1 + 2 * GridMonitor.bandVoltPct / 100);
  const opts = {
    responsive: true,
    maintainAspectRatio: false,
    animation: false,
    parsing: false,
    plugins: {
      legend: { display: nodes.length <= 8, labels: { boxWidth: 8, font: { size: 10 } } },
      tooltip: { callbacks: {
        label: (ctx) => `${ctx.dataset.label}: ${ctx.parsed.x.toFixed(1)} V, ${ctx.parsed.y.toFixed(2)} kVAr`,
      } },
    },
    scales: {
      x: {
        type: "linear",
        min: vMin, max: vMax,
        title: { display: true, text: "AC voltage V (V)" },
      },
      y: {
        title: { display: true, text: "Reactive Q (kVAr) — + lag / − lead" },
        grid: { color: "rgba(120,120,120,0.08)" },
      },
    },
  };
  const chart = _gmEnsureChart("gmChartQv", "scatter", datasets, opts);
  if (chart) {
    chart.data.datasets = datasets;
    chart.update("none");
  }
}

function _gmRenderDpDt(nodes) {
  // Time-series of dP/dt per node, scaled to kW/s.
  const datasets = nodes.map((n) => {
    const ip = n.inverter_ip;
    const slave = n.slave;
    const color = _gmPaletteHash(`${ip}#${slave}`);
    const data = [];
    // Compute dP/dt at every sample using running diff over the series.
    const s = n.series || [];
    for (let i = 1; i < s.length; i++) {
      const a = s[i], b = s[i - 1];
      const dt = (a.ts_ms - b.ts_ms) / 1000;
      if (dt > 0 && dt < 60 && a.pac_w != null && b.pac_w != null) {
        data.push({ x: a.ts_ms, y: (a.pac_w - b.pac_w) / dt / 1000 });
      }
    }
    return {
      label: `${ip}/${slave}`,
      borderColor: color,
      backgroundColor: color,
      pointRadius: 1.5,
      showLine: true,
      tension: 0.2,
      borderWidth: 1.4,
      data,
    };
  });
  const opts = {
    responsive: true,
    maintainAspectRatio: false,
    animation: false,
    parsing: false,
    plugins: {
      legend: { display: nodes.length <= 8, labels: { boxWidth: 8, font: { size: 10 } } },
    },
    scales: {
      x: {
        type: "time",
        time: { displayFormats: { second: "HH:mm:ss", minute: "HH:mm" } },
        title: { display: true, text: "Time" },
      },
      y: {
        title: { display: true, text: "dP/dt (kW/s)" },
        grid: { color: "rgba(120,120,120,0.08)" },
      },
    },
  };
  const chart = _gmEnsureChart("gmChartDp", "line", datasets, opts);
  if (chart) {
    chart.data.datasets = datasets;
    chart.update("none");
  }
}

function _gmRenderPfTimeline(nodes) {
  const datasets = nodes.map((n) => {
    const ip = n.inverter_ip;
    const slave = n.slave;
    const color = _gmPaletteHash(`${ip}#${slave}`);
    const data = (n.series || [])
      .filter((s) => s.pf != null)
      .map((s) => ({ x: s.ts_ms, y: s.pf }));
    return {
      label: `${ip}/${slave}`,
      borderColor: color,
      backgroundColor: color,
      pointRadius: 1.5,
      showLine: true,
      tension: 0.2,
      borderWidth: 1.4,
      data,
    };
  });
  const opts = {
    responsive: true,
    maintainAspectRatio: false,
    animation: false,
    parsing: false,
    plugins: {
      legend: { display: nodes.length <= 8, labels: { boxWidth: 8, font: { size: 10 } } },
    },
    scales: {
      x: {
        type: "time",
        time: { displayFormats: { second: "HH:mm:ss", minute: "HH:mm" } },
        title: { display: true, text: "Time" },
      },
      y: {
        min: 0.85, max: 1.0,
        title: { display: true, text: "Power factor |cos φ|" },
        grid: { color: "rgba(120,120,120,0.08)" },
      },
    },
  };
  const chart = _gmEnsureChart("gmChartPfTs", "line", datasets, opts);
  if (chart) {
    chart.data.datasets = datasets;
    chart.update("none");
  }
}

function _gmRenderChips(plant) {
  const wrap = document.getElementById("gmChips");
  if (!wrap) return;
  if (!plant || plant.fresh_count === 0) {
    wrap.innerHTML = '<span class="cmp-badge cmp-badge-grey">No live frames yet — start the poller / wait for first 5-sec tick.</span>';
    return;
  }
  const fHz = plant.plant_freq_hz_avg;
  const vAvg = plant.plant_vac_v_avg;
  const pacKw = plant.plant_pac_kw;
  const qacKvar = plant.plant_qac_kvar;
  const inBandF = fHz != null && fHz >= GridMonitor.bandFreqContinuous[0] && fHz <= GridMonitor.bandFreqContinuous[1];
  const inBandV = vAvg != null && Math.abs(vAvg - GridMonitor.voltNominalV) / GridMonitor.voltNominalV <= GridMonitor.bandVoltPct / 100;
  wrap.innerHTML = `
    <span class="cmp-badge cmp-badge-blue">Nodes fresh ${plant.fresh_count}/${plant.total_count}</span>
    <span class="cmp-badge ${inBandF ? "cmp-badge-green" : "cmp-badge-amber"}">f = ${fHz == null ? "—" : fHz.toFixed(3) + " Hz"} ${inBandF ? "✓ band" : "⚠ outside continuous band"}</span>
    <span class="cmp-badge ${inBandV ? "cmp-badge-green" : "cmp-badge-amber"}">V̄ = ${vAvg == null ? "—" : vAvg.toFixed(1) + " V"} ${inBandV ? "✓ ±5%" : "⚠ outside ±5%"}</span>
    <span class="cmp-badge cmp-badge-grey">P = ${pacKw.toFixed(1)} kW</span>
    <span class="cmp-badge cmp-badge-grey">Q = ${qacKvar.toFixed(2)} kVAr</span>
  `;
}

async function _gmPoll() {
  const panel = document.getElementById("gridMonitorPanel");
  if (!panel || panel.offsetParent === null) return;     // pane not visible
  try {
    const r = await fetch("/api/grid-code/live", { cache: "no-store" });
    if (!r.ok) return;
    const data = await r.json();
    if (!data?.ok) return;
    _gmRenderChips(data.plant);
    const nodes = Array.isArray(data.nodes) ? data.nodes : [];
    _gmRenderScatterPf(nodes);
    _gmRenderScatterQv(nodes);
    _gmRenderDpDt(nodes);
    _gmRenderPfTimeline(nodes);
  } catch (_) { /* ignore transient network errors */ }
}

function startGridMonitor() {
  if (GridMonitor.pollTimer) return;
  _gmPoll();
  GridMonitor.pollTimer = setInterval(_gmPoll, GridMonitor.pollMs);
}
function stopGridMonitor() {
  if (!GridMonitor.pollTimer) return;
  clearInterval(GridMonitor.pollTimer);
  GridMonitor.pollTimer = null;
}

// ─── end Slice ζ Grid Code UI ───────────────────────────────────────────────

function togglePlantCapSchedule() {
  const wrap    = $("plantCapScheduleWrap");
  const chevron = $("plantCapScheduleChevron");
  if (!wrap) return;
  const isHidden = wrap.hidden;
  wrap.hidden = !isHidden;
  if (chevron) chevron.textContent = isHidden ? "▲" : "▼";
  if (isHidden) loadCapScheduleStatus().catch(() => {});
}

function renderPlantCapSchedChips() {
  const container = $("plantCapSchedChips");
  if (!container) return;
  const schedules = State.capSchedules.schedules;
  if (!schedules || !schedules.length) {
    container.innerHTML = '<div class="plant-cap-sched-chips-empty">No schedules configured.</div>';
    return;
  }
  container.innerHTML = "";
  schedules.forEach((sched) => {
    const { label, cls } = _capSchedStateInfo(sched);
    const chip = el("div", `plant-cap-sched-chip plant-cap-sched-chip--${cls}`);

    const timeSpan = el("span", "plant-cap-sched-chip-time");
    timeSpan.textContent = `${sched.start_time} – ${sched.stop_time}`;
    chip.appendChild(timeSpan);

    const nameSpan = el("span", "plant-cap-sched-chip-name");
    nameSpan.textContent = sched.name || "Schedule";
    chip.appendChild(nameSpan);

    const badgeSpan = el("span", `plant-cap-sched-chip-badge plant-cap-sched-chip-badge--${cls}`);
    badgeSpan.textContent = label;
    chip.appendChild(badgeSpan);

    const editBtn = el("button", "plant-cap-sched-chip-edit");
    editBtn.type = "button";
    editBtn.title = "Edit this schedule";
    editBtn.dataset.schedId = String(sched.id);
    editBtn.innerHTML = '<span class="mdi mdi-pencil-outline" aria-hidden="true"></span>';
    chip.appendChild(editBtn);

    container.appendChild(chip);
  });
}

function togglePlantCapHistory() {
  const wrap = $("plantCapHistoryWrap");
  const chevron = $("plantCapHistoryChevron");
  if (!wrap) return;
  const isHidden = wrap.hidden;
  wrap.hidden = !isHidden;
  if (chevron) chevron.textContent = isHidden ? "▲" : "▼";
  if (isHidden) loadPlantCapHistory();
}

async function loadPlantCapHistory() {
  const tbody = $("plantCapHistoryBody");
  if (!tbody) return;
  try {
    const data = await api("/api/plant-cap/history?limit=50", "GET", null, { progress: false });
    const rows = Array.isArray(data.history) ? data.history : [];
    if (!rows.length) {
      tbody.innerHTML = '<tr class="table-empty"><td colspan="6">No cap history yet.</td></tr>';
      return;
    }
    tbody.innerHTML = rows.map((r) => {
      const ts = r.ts ? new Date(Number(r.ts)).toLocaleString() : "—";
      const action = escapeHtml(String(r.action || "—"));
      const reason = escapeHtml(String(r.reason || "—"));
      const inv = r.inverter ? String(r.inverter) : "—";
      const node = r.node ? String(r.node) : "—";
      const result = escapeHtml(String(r.result || "—"));
      return `<tr><td>${ts}</td><td>${action}</td><td>${reason}</td><td>${inv}</td><td>${node}</td><td>${result}</td></tr>`;
    }).join("");
  } catch (err) {
    if (tbody) tbody.innerHTML = `<tr class="table-empty"><td colspan="6">Failed to load history: ${escapeHtml(err.message)}</td></tr>`;
  }
}

function normalizePlantCapStatusClient(raw) {
  const src = raw && typeof raw === "object" ? raw : {};
  return {
    enabled: Boolean(src.enabled),
    status: String(src.status || "idle"),
    reasonCode: String(src.reasonCode || "disabled"),
    reasonText: String(src.reasonText || "Plant-wide capping is disabled."),
    upperMw: src.upperMw == null ? null : Number(src.upperMw),
    lowerMw: src.lowerMw == null ? null : Number(src.lowerMw),
    currentPlantMw: src.currentPlantMw == null ? null : Number(src.currentPlantMw),
    warnings: Array.isArray(src.warnings) ? src.warnings : [],
    stepMetrics: src.stepMetrics && typeof src.stepMetrics === "object" ? src.stepMetrics : {},
    ownedStopped: Array.isArray(src.ownedStopped) ? src.ownedStopped : [],
    lastDecision: src.lastDecision && typeof src.lastDecision === "object" ? src.lastDecision : null,
    pendingAction: src.pendingAction && typeof src.pendingAction === "object" ? src.pendingAction : null,
    preview: src.preview && typeof src.preview === "object" ? src.preview : null,
    cooldownRemainingSec: Number(src.cooldownRemainingSec || 0),
    cooldownSec: Number(src.cooldownSec || 0),
    sequenceCustom: Array.isArray(src.sequenceCustom) ? src.sequenceCustom : [],
    gapMw: src.gapMw == null ? null : Number(src.gapMw),
  };
}

function formatPlantCapBandLabel(status) {
  if (status.upperMw == null || status.lowerMw == null) return "—";
  return `${Number(status.lowerMw).toFixed(3)} - ${Number(status.upperMw).toFixed(3)} MW`;
}

function renderPlantCapPreviewTable(previewRaw) {
  const tbody = $("plantCapPreviewBody");
  const meta = $("plantCapPreviewMeta");
  const stepHdr = $("plantCapPreviewStepHdr");
  if (!tbody || !meta || !stepHdr) return;
  const preview = previewRaw && typeof previewRaw === "object" ? previewRaw : null;
  if (!preview) {
    stepHdr.textContent = "Step kW";
    stepHdr.title =
      "Estimated plant output change for each candidate step in kW.";
    meta.textContent =
      "Preview the next stop/start decision before enabling control.";
    meta.title = meta.textContent;
    tbody.innerHTML =
      '<tr class="table-empty"><td colspan="7">No plant cap preview yet.</td></tr>';
    return;
  }
  const useRestart =
    preview.currentPlantKw < preview.lowerKw &&
    Array.isArray(preview.restartPlan) &&
    preview.restartPlan.length > 0;
  const rows = useRestart
    ? preview.restartPlan || []
    : (preview.stopPlan && preview.stopPlan.length
      ? preview.stopPlan
      : preview.restartPlan || []);
  const selectedInverter = useRestart
    ? preview.selectedRestart?.inverter
    : preview.selectedStop?.inverter;
  stepHdr.textContent = useRestart ? "Restart Est. kW" : "Live Pac kW";
  stepHdr.title = useRestart
    ? "Estimated plant output increase in kW if the controller restarts this inverter."
    : "Current live PAC contribution in kW that would be removed if the controller stops this inverter.";
  const recommended = String(preview.recommendedAction || "hold").toUpperCase();
  meta.textContent = `Recommended: ${recommended} · Current ${Number(
    preview.currentPlantMw || 0,
  ).toFixed(3)} MW · Band ${Number(preview.lowerMw || 0).toFixed(3)}-${Number(
    preview.upperMw || 0,
  ).toFixed(3)} MW`;
  meta.title = meta.textContent;
  if (!rows.length) {
    tbody.innerHTML =
      '<tr class="table-empty"><td colspan="7">No eligible inverter step is available for the current band.</td></tr>';
    return;
  }
  tbody.innerHTML = rows
    .map((row) => {
      const stepKw = useRestart ? row.restartEstimateKw : row.livePacKw;
      const selectedClass =
        Number(row.inverter || 0) === Number(selectedInverter || 0)
          ? " plant-cap-preview-selected"
          : "";
      const reason = String(row.decisionReason || "—");
      const rowTitle =
        `INV-${String(row.inverter || 0).padStart(2, "0")} · ` +
        `Nodes ${Number(row.enabledNodes || 0)} · ` +
        `Rated ${Number(row.ratedKw || 0).toFixed(1)} kW · ` +
        `Dependable ${Number(row.dependableKw || 0).toFixed(1)} kW · ` +
        `${useRestart ? "Restart estimate" : "Live PAC"} ${Number(stepKw || 0).toFixed(1)} kW · ` +
        `Projected plant ${Number(row.projectedPlantMw || 0).toFixed(3)} MW · ` +
        reason;
      return `
        <tr class="${selectedClass.trim()}" title="${rowTitle}">
          <td title="Inverter number under evaluation.">INV-${String(row.inverter || 0).padStart(2, "0")}</td>
          <td title="Configured enabled node count for this inverter.">${Number(row.enabledNodes || 0)}</td>
          <td title="Node-adjusted rated inverter capacity in kW.">${Number(row.ratedKw || 0).toFixed(1)}</td>
          <td title="Node-adjusted dependable capacity in kW used for conservative planning.">${Number(row.dependableKw || 0).toFixed(1)}</td>
          <td title="${useRestart ? "Estimated plant output increase if this inverter is restarted." : "Current live PAC contribution that would be removed if this inverter is stopped."}">${Number(stepKw || 0).toFixed(1)}</td>
          <td title="Projected total plant output after applying this step.">${Number(row.projectedPlantMw || 0).toFixed(3)}</td>
          <td title="${reason}">${reason}</td>
        </tr>`;
    })
    .join("");
}

function renderPlantCapPanel() {
  syncPlantCapPanelCollapsedUi();
  const currentMwEl = $("plantCapCurrentMw");
  const bandEl = $("plantCapBandValue");
  const modeEl = $("plantCapModeValue");
  const statusEl = $("plantCapStatusText");
  const reasonEl = $("plantCapReasonText");
  const lastActionEl = $("plantCapLastActionText");
  const cooldownEl = $("plantCapCooldownText");
  const curtailedEl = $("plantCapCurtailedText");
  const controllableEl = $("plantCapControllableText");
  const pendingEl = $("plantCapPendingText");
  const exemptedEl = $("plantCapExemptedText");
  const controlledWrap = $("plantCapControlledWrap");
  const controlledBody = $("plantCapControlledBody");
  const warningsEl = $("plantCapServerWarnings");
  const releaseBtn = $("btnPlantCapRelease");
  const previewMetaEl = $("plantCapPreviewMeta");
  if (!currentMwEl || !bandEl || !modeEl || !statusEl || !reasonEl || !lastActionEl || !warningsEl) {
    return;
  }
  const remoteBadge = $("plantCapRemoteBadge");
  if (remoteBadge) {
    remoteBadge.hidden = !isClientModeActive();
  }
  const status = normalizePlantCapStatusClient(State.plantCap.status || {});
  currentMwEl.textContent =
    status.currentPlantMw == null ? "—" : `${Number(status.currentPlantMw).toFixed(3)} MW`;
  bandEl.textContent = formatPlantCapBandLabel(status);
  const modeText = status.enabled ? "Enabled" : status.status === "paused" ? "Paused" : "Idle";
  modeEl.textContent = modeText;
  statusEl.textContent = String(status.status || "idle").toUpperCase();
  reasonEl.textContent = status.reasonText || "Plant-wide capping is disabled.";
  if (releaseBtn) {
    releaseBtn.disabled = !status.ownedStopped.length;
  }
  /* Last Action */
  if (status.lastDecision) {
    const stamp = status.lastDecision.at ? fmtDateTime(status.lastDecision.at) : "";
    const label = String(status.lastDecision.action || "").toUpperCase();
    lastActionEl.textContent = stamp
      ? `${label} INV-${String(status.lastDecision.inverter || 0).padStart(2, "0")} @ ${stamp}`
      : `${label} INV-${String(status.lastDecision.inverter || 0).padStart(2, "0")}`;
  } else if (status.cooldownRemainingSec > 0) {
    lastActionEl.textContent = `Settling (${status.cooldownRemainingSec}s remaining)`;
  } else {
    lastActionEl.textContent = "—";
  }
  /* Cooldown */
  if (cooldownEl) {
    if (status.cooldownRemainingSec > 0) {
      cooldownEl.textContent = `Settling (${status.cooldownRemainingSec}s)`;
    } else if (status.cooldownSec > 0) {
      cooldownEl.textContent = `${status.cooldownSec}s configured`;
    } else {
      cooldownEl.textContent = "—";
    }
  }
  /* Curtailed */
  if (curtailedEl) {
    const totalKw = status.ownedStopped.reduce((sum, e) => sum + Number(e.pacBeforeStopKw || 0), 0);
    const totalMw = totalKw / 1000;
    const invCount = status.ownedStopped.length;
    curtailedEl.textContent = invCount
      ? `${totalMw.toFixed(3)} MW (${invCount} inv)`
      : "0.000 MW";
  }
  /* Controllable */
  if (controllableEl) {
    const cnt = Number(status.stepMetrics.controllableInverterCount || 0);
    controllableEl.textContent = cnt ? `${cnt} inverters` : "0 inverters";
  }
  /* Pending */
  if (pendingEl) {
    if (status.pendingAction) {
      const pType = String(status.pendingAction.type || status.pendingAction.action || "ACTION").toUpperCase();
      const pInv = status.pendingAction.inverter;
      pendingEl.textContent = pInv != null
        ? `${pType} INV-${String(pInv).padStart(2, "0")} in progress`
        : `${pType} in progress`;
    } else {
      pendingEl.textContent = "None";
    }
  }
  /* Exempted */
  if (exemptedEl) {
    if (status.sequenceCustom.length) {
      exemptedEl.textContent = status.sequenceCustom
        .map((n) => `INV-${String(n).padStart(2, "0")}`)
        .join(", ");
    } else {
      exemptedEl.textContent = "None";
    }
  }
  /* Controlled inverters mini-table */
  if (controlledWrap && controlledBody) {
    if (status.ownedStopped.length) {
      controlledWrap.hidden = false;
      const sorted = [...status.ownedStopped].sort((a, b) => {
        return Number(b.stoppedAt || 0) - Number(a.stoppedAt || 0);
      });
      const nowMs = Date.now();
      controlledBody.innerHTML = sorted.map((entry) => {
        const inv = `INV-${String(entry.inverter || 0).padStart(2, "0")}`;
        const stoppedTs = Number(entry.stoppedAt || 0);
        const stoppedAt = stoppedTs ? fmtTime(stoppedTs) : "—";
        const elapsedMs = stoppedTs ? Math.max(0, nowMs - stoppedTs) : 0;
        const elapsedSec = Math.floor(elapsedMs / 1000);
        const durH = Math.floor(elapsedSec / 3600);
        const durM = Math.floor((elapsedSec % 3600) / 60);
        const durS = elapsedSec % 60;
        const duration = elapsedMs
          ? (durH > 0 ? `${durH}h ${String(durM).padStart(2, "0")}m` : `${durM}m ${String(durS).padStart(2, "0")}s`)
          : "—";
        const pac = Number(entry.pacBeforeStopKw || 0).toFixed(1);
        const nodes = Number(entry.enabledNodes || 0);
        const rated = Number(entry.ratedKw || 0).toFixed(1);
        const dependable = Number(entry.dependableKw || 0).toFixed(1);
        return `<tr title="${inv} stopped at ${stoppedAt} (${duration} ago), ${pac} kW removed, ${nodes} nodes, rated ${rated} kW, dependable ${dependable} kW.">
          <td>${inv}</td><td>${stoppedAt}</td><td>${duration}</td><td>${pac}</td><td>${nodes}</td><td>${rated}</td><td>${dependable}</td>
        </tr>`;
      }).join("");
    } else {
      controlledWrap.hidden = true;
      controlledBody.innerHTML = "";
    }
  }
  currentMwEl.closest(".plant-cap-metric")?.setAttribute(
    "title",
    status.currentPlantMw == null
      ? "Current total plant MW from fresh live PAC data used by the cap controller."
      : `Current total plant MW from fresh live PAC data: ${Number(status.currentPlantMw).toFixed(3)} MW.`,
  );
  bandEl.closest(".plant-cap-metric")?.setAttribute(
    "title",
    status.upperMw == null || status.lowerMw == null
      ? "Configured lower and upper MW cap band."
      : `Configured MW Cap band: ${Number(status.lowerMw).toFixed(3)} to ${Number(status.upperMw).toFixed(3)} MW.`,
  );
  modeEl.closest(".plant-cap-metric")?.setAttribute(
    "title",
    `Current controller mode: ${modeText}. Idle means disabled, Paused means blocked by safety or freshness checks, and Enabled means active.`,
  );
  statusEl.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    `Current MW Cap controller state: ${statusEl.textContent}.`,
  );
  reasonEl.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    `Current controller reason: ${reasonEl.textContent}`,
  );
  cooldownEl?.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    status.cooldownRemainingSec > 0
      ? `Settling after last action: ${status.cooldownRemainingSec}s remaining of ${status.cooldownSec}s configured.`
      : status.cooldownSec > 0
        ? `Configured settle time between controller actions: ${status.cooldownSec}s.`
        : "Cooldown or settling time between controller actions.",
  );
  curtailedEl?.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    status.ownedStopped.length
      ? `Total MW curtailed by ${status.ownedStopped.length} controller-stopped inverter(s) based on PAC at stop time.`
      : "No inverter is currently curtailed by the MW Cap controller.",
  );
  controllableEl?.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    `Number of inverters eligible for automatic stop selection: ${Number(status.stepMetrics.controllableInverterCount || 0)}.`,
  );
  pendingEl?.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    status.pendingAction
      ? `An in-flight controller command is executing: ${pendingEl.textContent}.`
      : "No controller action is currently in progress.",
  );
  exemptedEl?.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    status.sequenceCustom.length
      ? `Inverters exempt from automatic stop: ${exemptedEl.textContent}.`
      : "No inverters are exempted from automatic stop selection.",
  );
  lastActionEl.closest(".plant-cap-status-item")?.setAttribute(
    "title",
    lastActionEl.textContent === "—"
      ? "No automatic stop or restart action has been recorded for this session."
      : `Most recent controller action or settling state: ${lastActionEl.textContent}.`,
  );
  const warnings = Array.isArray(status.warnings) ? status.warnings : [];
  if (!warnings.length) {
    warningsEl.className = "plant-cap-server-warnings";
    warningsEl.textContent =
      "Server-side planner status is normal. Preview or enable the controller to apply the configured cap band.";
  } else {
    const critical = warnings.some((warning) => warning?.severity === "critical");
    warningsEl.className = `plant-cap-server-warnings ${critical ? "critical" : "warning"}`;
    const visibleMsgs = warnings
      .slice(0, 2)
      .map((warning) => String(warning?.message || "").trim())
      .filter(Boolean);
    const extra = warnings.length - visibleMsgs.length;
    warningsEl.textContent =
      visibleMsgs.join(" ") + (extra > 0 ? ` (+${extra} more)` : "");
  }
  warningsEl.title = warnings.length
    ? warnings
      .map((warning) => String(warning?.message || "").trim())
      .filter(Boolean)
      .join(" ")
    : "Server-side planner warnings, safety blocks, or advisory messages.";
  if (previewMetaEl) {
    previewMetaEl.title = previewMetaEl.textContent || "Planner summary for the next cap decision.";
  }
  renderPlantCapPreviewTable(
    State.plantCap.preview || status.preview || null,
  );
  renderPlantCapExportLimit();
  if (State.currentPage === "plant-cap") syncPlantCapPageToolbar();
}

function renderPlantCapExportLimit() {
  const el_ = $("plantCapExportLimitMw");
  if (!el_) return;
  const lim = Number(State.settings.forecastExportLimitMw || 24);
  el_.textContent = Number.isFinite(lim) ? `${lim.toFixed(1)} MW` : "—";
}

function applyPlantCapStatusClient(statusRaw, options = {}) {
  const normalized = normalizePlantCapStatusClient(statusRaw);
  State.plantCap.status = normalized;
  if (!options.preservePreview) {
    State.plantCap.preview = normalized.preview || State.plantCap.preview;
  } else if (normalized.preview && !State.plantCap.preview) {
    State.plantCap.preview = normalized.preview;
  }
  renderPlantCapPanel();
}

function buildInverterGrid() {
  const grid = $("invGrid");
  if (!grid) return;
  grid.innerHTML = "";
  State.nodeOrderSig = {};
  const count = State.settings.inverterCount;
  const nodes = State.settings.nodeCount || 4;
  const storedOrder = getStoredInverterCardOrder();
  const seen = new Set();
  const ordered = [];
  let camPlaced = false;
  if (storedOrder) {
    for (const i of storedOrder) {
      if (i === "cam" && !camPlaced) { ordered.push("cam"); camPlaced = true; }
      else if (typeof i === "number" && i >= 1 && i <= count && !seen.has(i)) { ordered.push(i); seen.add(i); }
    }
  }
  for (let i = 1; i <= count; i++) {
    if (!seen.has(i)) ordered.push(i);
  }
  if (!camPlaced) ordered.push("cam");
  const frag = document.createDocumentFragment();
  frag.appendChild(buildBulkControlPanel());
  for (const i of ordered) {
    if (i === "cam") frag.appendChild(buildCameraCard());
    else frag.appendChild(buildInverterCard(i, nodes));
  }
  grid.appendChild(frag);
  applyInverterGridLayout(State.settings.invGridLayout);
  initInverterGridDrag();
  initCameraPlayer();
}

function initInverterGridDrag() {
  const grid = $("invGrid");
  if (!grid || grid.dataset.dragInit === "1") return;
  grid.dataset.dragInit = "1";
  let dragSrcId = null;
  let placeholder = null;

  function removePlaceholder() {
    if (placeholder && placeholder.parentNode) placeholder.parentNode.removeChild(placeholder);
    placeholder = null;
  }

  // Returns the DOM node to insertBefore (null = append at end).
  // Splits the target card at its vertical midpoint: top half → before, bottom half → after.
  function getInsertRef(targetCard, mouseY) {
    const r = targetCard.getBoundingClientRect();
    return mouseY < r.top + r.height / 2 ? targetCard : (targetCard.nextSibling || null);
  }

  const DRAG_SEL = ".inv-card[draggable='true'], .camera-card[draggable='true']";
  function findDragCard(target) { return target.closest(DRAG_SEL); }

  grid.addEventListener("dragstart", (e) => {
    const card = findDragCard(e.target);
    if (!card) return;
    // Prevent drag from starting on interactive elements inside camera card
    if (card.classList.contains("camera-card") && e.target.closest(".cam-controls, button, input, select")) {
      e.preventDefault();
      return;
    }
    dragSrcId = card.id;
    requestAnimationFrame(() => card.classList.add("dragging"));
    e.dataTransfer.effectAllowed = "move";
    e.dataTransfer.setData("text/plain", card.id);
  });

  grid.addEventListener("dragend", () => {
    grid.querySelectorAll(".dragging, .drag-over").forEach(c => {
      c.classList.remove("dragging", "drag-over");
    });
    removePlaceholder();
    dragSrcId = null;
  });

  grid.addEventListener("dragover", (e) => {
    e.preventDefault();
    if (!dragSrcId) return;
    const card = findDragCard(e.target);
    if (!card || card.id === dragSrcId) return;
    e.dataTransfer.dropEffect = "move";

    const insertRef = getInsertRef(card, e.clientY);
    if (placeholder && placeholder.nextSibling === insertRef) return;

    if (placeholder && placeholder.parentNode) placeholder.parentNode.removeChild(placeholder);

    placeholder = document.createElement("div");
    placeholder.className = "inv-card drag-placeholder";
    placeholder.setAttribute("aria-hidden", "true");
    grid.insertBefore(placeholder, insertRef);
  });

  grid.addEventListener("dragleave", (e) => {
    if (!e.relatedTarget || !grid.contains(e.relatedTarget)) {
      grid.querySelectorAll(".drag-over").forEach(c => c.classList.remove("drag-over"));
      removePlaceholder();
    }
  });

  grid.addEventListener("drop", (e) => {
    e.preventDefault();
    const srcCard = dragSrcId ? $(dragSrcId) : null;
    if (srcCard && placeholder && placeholder.parentNode) {
      grid.insertBefore(srcCard, placeholder);
    } else if (srcCard) {
      const targetCard = findDragCard(e.target);
      if (targetCard && targetCard.id !== dragSrcId) grid.insertBefore(srcCard, targetCard);
    }
    grid.querySelectorAll(".drag-over").forEach(c => c.classList.remove("drag-over"));
    removePlaceholder();
    dragSrcId = null;
    // Persist order: inverter cards as numbers, camera card as "cam"
    const newOrder = [...grid.querySelectorAll(DRAG_SEL)]
      .map(c => c.id === "cameraCard" ? "cam" : parseInt(c.id.replace("inv-card-", ""), 10))
      .filter(v => v === "cam" || (Number.isFinite(v) && v > 0));
    persistInverterCardOrder(newOrder);
  });
}

function currentOperator() {
  const inState = String(State.settings.operatorName || "").trim();
  if (inState) return inState;
  const fromInput = String($("setOperatorName")?.value || "").trim();
  return fromInput || "OPERATOR";
}

function currentChatMachine() {
  return normalizeOperationModeValue(State.settings.operationMode);
}

function getChatModeLabel(machine = currentChatMachine()) {
  return normalizeChatMachineClient(machine, "gateway") === "remote"
    ? "Remote"
    : "Server";
}

function buildChatSenderLabel(row) {
  const machine = normalizeChatMachineClient(row?.from_machine, currentChatMachine());
  const explicit = String(row?.from_name || "").trim();
  if (explicit) return explicit;
  return `${currentOperator()} - ${getChatModeLabel(machine)}`;
}

function normalizeChatMachineClient(value, def = "gateway") {
  return String(value || def).trim().toLowerCase() === "remote"
    ? "remote"
    : "gateway";
}

function isChatInboundRow(row, machine = currentChatMachine()) {
  const ownMachine = normalizeChatMachineClient(machine, currentChatMachine());
  return (
    !!row &&
    normalizeChatMachineClient(row.to_machine, ownMachine) === ownMachine &&
    normalizeChatMachineClient(row.from_machine, ownMachine) !== ownMachine
  );
}

function sanitizeChatRowClient(row) {
  if (!row || typeof row !== "object") return null;
  const id = Math.max(0, Math.trunc(Number(row.id || 0)));
  if (!id) return null;
  const fromMachine = normalizeChatMachineClient(row.from_machine, "gateway");
  const toMachine = normalizeChatMachineClient(
    row.to_machine,
    fromMachine === "remote" ? "gateway" : "remote",
  );
  return {
    id,
    ts: Math.max(0, Math.trunc(Number(row.ts || 0))),
    from_machine: fromMachine,
    to_machine: toMachine,
    from_name: String(row.from_name || "").trim().slice(0, 160),
    message: String(row.message || ""),
    read_ts:
      row.read_ts == null || row.read_ts === ""
        ? null
        : Math.max(0, Math.trunc(Number(row.read_ts || 0))),
  };
}

function syncChatRuntimeFromRows() {
  const machine = currentChatMachine();
  let lastInboundId = 0;
  let lastReadId = 0;
  let unread = 0;
  for (const row of State.chatMessages) {
    if (normalizeChatMachineClient(row.to_machine, machine) !== machine) continue;
    lastInboundId = Math.max(lastInboundId, Number(row.id || 0));
    if (row.read_ts) lastReadId = Math.max(lastReadId, Number(row.id || 0));
    else unread += 1;
  }
  State.chatLastInboundId = lastInboundId;
  State.chatLastReadId = Math.max(Number(State.chatLastReadId || 0), lastReadId);
  State.chatUnread = State.chatOpen ? 0 : unread;
}

function mergeChatRows(rows) {
  const merged = new Map();
  for (const row of State.chatMessages || []) {
    const normalized = sanitizeChatRowClient(row);
    if (normalized) merged.set(normalized.id, normalized);
  }
  for (const row of Array.isArray(rows) ? rows : []) {
    const normalized = sanitizeChatRowClient(row);
    if (!normalized) continue;
    const prev = merged.get(normalized.id);
    if (!prev) {
      merged.set(normalized.id, normalized);
      continue;
    }
    merged.set(normalized.id, {
      ...prev,
      ...normalized,
      read_ts: normalized.read_ts || prev.read_ts || null,
    });
  }
  State.chatMessages = Array.from(merged.values())
    .sort((a, b) => Number(a.id || 0) - Number(b.id || 0))
    .slice(-CHAT_THREAD_LIMIT);
  syncChatRuntimeFromRows();
  renderChatSendState();
  return State.chatMessages;
}

function renderChatBadge() {
  const badge = $("chatBadge");
  if (!badge) return;
  const count = Math.max(0, Math.trunc(Number(State.chatUnread || 0)));
  if (count > 0) {
    badge.hidden = false;
    badge.textContent = count > 99 ? "99+" : String(count);
  } else {
    badge.hidden = true;
    badge.textContent = "0";
  }
}

function renderChatSendState() {
  const btn = $("chatSend");
  const clearBtn = $("chatClear");
  const input = $("chatInput");
  const busy = !!State.chatPendingSend || !!State.chatPendingClear;
  if (btn) {
    btn.disabled = busy;
    btn.textContent = State.chatPendingSend ? "Sending..." : "Send";
  }
  if (clearBtn) {
    clearBtn.disabled =
      busy || !Array.isArray(State.chatMessages) || State.chatMessages.length === 0;
    clearBtn.textContent = State.chatPendingClear ? "Clearing..." : "Clear";
  }
  if (input) input.disabled = busy;
}

function renderChatThread() {
  const thread = $("chatThread");
  if (!thread) return;
  const rows = Array.isArray(State.chatMessages) ? State.chatMessages : [];
  const frag = document.createDocumentFragment();
  if (!rows.length) {
    const empty = el("div", "chat-empty");
    empty.textContent = "No recent operator messages.";
    frag.appendChild(empty);
  } else {
    const machine = currentChatMachine();
    for (const row of rows) {
      const self = normalizeChatMachineClient(row.from_machine, machine) === machine;
      const item = el("div", `chat-message${self ? " is-self" : ""}`);
      const meta = el("div", "chat-message-meta");
      meta.textContent = `${buildChatSenderLabel(row)} • ${fmtDateTime(row.ts)}`;
      const body = el("div", "chat-message-body");
      body.textContent = String(row.message || "");
      item.appendChild(meta);
      item.appendChild(body);
      frag.appendChild(item);
    }
  }
  thread.textContent = "";
  thread.appendChild(frag);
  if (State.chatOpen) {
    requestAnimationFrame(() => {
      thread.scrollTop = thread.scrollHeight;
    });
  }
}

function clearChatDismissTimer() {
  if (State.chatDismissTimer) {
    clearTimeout(State.chatDismissTimer);
    State.chatDismissTimer = null;
  }
}

function chatHasProtectedDraft() {
  const input = $("chatInput");
  if (!input) return false;
  return document.activeElement === input && String(input.value || "").trim().length > 0;
}

function resetChatDismissTimer() {
  clearChatDismissTimer();
  if (!State.chatOpen) return;
  if (State.chatPendingSend) return;
  if (State.chatPendingClear) return;
  if (chatHasProtectedDraft()) return;
  State.chatDismissTimer = setTimeout(() => {
    closeChatPanel();
  }, CHAT_DISMISS_MS);
}

function openChatPanel() {
  const panel = $("chatPanel");
  const bubble = $("chatBubble");
  if (!panel || !bubble) return;
  State.chatOpen = true;
  panel.classList.add("chat-panel--open");
  panel.setAttribute("aria-hidden", "false");
  bubble.setAttribute("aria-expanded", "true");
  State.chatUnread = 0;
  renderChatBadge();
  renderChatThread();
  markChatRead().catch((err) => {
    console.warn("[chat] mark read failed:", err.message);
  });
  resetChatDismissTimer();
}

function closeChatPanel() {
  const panel = $("chatPanel");
  const bubble = $("chatBubble");
  if (!panel || !bubble) return;
  State.chatOpen = false;
  panel.classList.remove("chat-panel--open");
  panel.setAttribute("aria-hidden", "true");
  bubble.setAttribute("aria-expanded", "false");
  clearChatDismissTimer();
}

function applyChatClearedState({ preserveDraft = true } = {}) {
  State.chatMessages = [];
  State.chatUnread = 0;
  State.chatLastReadId = 0;
  State.chatLastInboundId = 0;
  State.chatReadInFlight = false;
  State.chatPendingReadUpToId = 0;
  State.chatHistoryLoaded = true;
  if (!preserveDraft && $("chatInput")) $("chatInput").value = "";
  renderChatSendState();
  renderChatBadge();
  renderChatThread();
  if (State.chatOpen) resetChatDismissTimer();
}

async function loadChatHistory(options = {}) {
  try {
    const payload = await api(
      `/api/chat/messages?mode=thread&limit=${CHAT_THREAD_LIMIT}`,
      "GET",
      null,
      { progress: false },
    );
    mergeChatRows(payload?.rows);
    State.chatHistoryLoaded = true;
    renderChatBadge();
    if (State.chatOpen) {
      renderChatThread();
      await markChatRead();
      resetChatDismissTimer();
    }
    return State.chatMessages;
  } catch (err) {
    State.chatHistoryLoaded = false;
    if (!options?.silent) {
      console.warn("[chat] history load failed:", err.message);
    }
    return [];
  }
}

async function markChatRead(forcedUpToId = 0) {
  const machine = currentChatMachine();
  let upToId = Math.max(0, Math.trunc(Number(forcedUpToId || 0)));
  for (const row of State.chatMessages || []) {
    if (!isChatInboundRow(row, machine)) continue;
    upToId = Math.max(upToId, Number(row.id || 0));
  }
  if (!upToId || upToId <= Number(State.chatLastReadId || 0)) {
    State.chatUnread = 0;
    renderChatBadge();
    return 0;
  }
  if (State.chatReadInFlight) {
    State.chatPendingReadUpToId = Math.max(
      Number(State.chatPendingReadUpToId || 0),
      upToId,
    );
    return 0;
  }
  State.chatReadInFlight = true;
  try {
    const payload = await api(
      "/api/chat/read",
      "POST",
      { upToId },
      { progress: false },
    );
    const readTs = Date.now();
    State.chatLastReadId = Math.max(Number(State.chatLastReadId || 0), upToId);
    State.chatMessages = (State.chatMessages || []).map((row) => {
      if (!isChatInboundRow(row, machine)) return row;
      if (Number(row.id || 0) > upToId) return row;
      if (row.read_ts) return row;
      return {
        ...row,
        read_ts: readTs,
      };
    });
    State.chatUnread = 0;
    renderChatBadge();
    return Math.max(0, Math.trunc(Number(payload?.updated || 0)));
  } catch (err) {
    console.warn("[chat] read sync failed:", err.message);
    return 0;
  } finally {
    State.chatReadInFlight = false;
    const pending = Math.max(0, Math.trunc(Number(State.chatPendingReadUpToId || 0)));
    State.chatPendingReadUpToId = 0;
    if (pending > Number(State.chatLastReadId || 0)) {
      markChatRead(pending).catch(() => {});
    }
  }
}

function playChatSound() {
  try {
    const ctx = getOrCreateAlarmAudioCtx();
    if (!ctx || ctx.state !== "running") {
      State.chatAudioReady = false;
      return;
    }
    State.chatAudioReady = true;
    const gain = ctx.createGain();
    gain.gain.value = 0.018;
    gain.connect(ctx.destination);
    const t0 = ctx.currentTime;
    [660, 880].forEach((freq, idx) => {
      const osc = ctx.createOscillator();
      osc.type = "sine";
      osc.frequency.value = freq;
      osc.connect(gain);
      const startAt = t0 + idx * 0.105;
      osc.start(startAt);
      osc.stop(startAt + 0.085);
    });
  } catch (err) {
    console.warn("[chat] sound failed:", err.message);
  }
}

function handleIncomingChatMessage(row) {
  const normalized = sanitizeChatRowClient(row);
  if (!normalized) return;
  const hadRow = (State.chatMessages || []).some(
    (item) => Number(item?.id || 0) === normalized.id,
  );
  const inbound = isChatInboundRow(normalized);
  mergeChatRows([normalized]);
  renderChatBadge();
  if (!hadRow && inbound) {
    openChatPanel();
    playChatSound();
    return;
  }
  if (State.chatOpen) {
    renderChatThread();
    if (inbound) {
      markChatRead(normalized.id).catch((err) => {
        console.warn("[chat] mark read failed:", err.message);
      });
    }
  }
  resetChatDismissTimer();
}

function handleChatCleared() {
  applyChatClearedState({ preserveDraft: true });
}

async function sendChatMessage() {
  const input = $("chatInput");
  if (!input || State.chatPendingSend || State.chatPendingClear) return;
  const draft = String(input.value || "").replace(/\r\n?/g, "\n");
  const message = draft.trim();
  if (!message) {
    input.value = message;
    resetChatDismissTimer();
    return;
  }
  if (message.length > 500) {
    showToast("Message must be 500 characters or fewer.", "warning", 3200);
    return;
  }
  State.chatPendingSend = true;
  renderChatSendState();
  try {
    const payload = await api(
      "/api/chat/send",
      "POST",
      { message },
      { progress: false },
    );
    const row = sanitizeChatRowClient(payload?.row);
    if (!row) throw new Error("Chat send completed without a message row.");
    mergeChatRows([row]);
    input.value = "";
    if (State.chatOpen) renderChatThread();
    renderChatBadge();
    resetChatDismissTimer();
  } catch (err) {
    showToast(String(err?.message || "Gateway unavailable. Message not sent."), "warning", 3600);
  } finally {
    State.chatPendingSend = false;
    renderChatSendState();
    if (State.chatOpen) resetChatDismissTimer();
  }
}

async function clearChatMessages() {
  if (State.chatPendingSend || State.chatPendingClear) return;
  if (!Array.isArray(State.chatMessages) || State.chatMessages.length === 0) {
    renderChatSendState();
    return;
  }
  const ok = await appConfirm(
    "Clear Operator Messages",
    "Clear the current operator message thread?\n\nThis removes the shared message history for both Server and Remote panels.",
    { ok: "Clear Messages", cancel: "Keep Messages" },
  );
  if (!ok) {
    resetChatDismissTimer();
    return;
  }
  State.chatPendingClear = true;
  renderChatSendState();
  try {
    await api("/api/chat/clear", "POST", {}, { progress: false });
    applyChatClearedState({ preserveDraft: true });
    showToast("Operator message history cleared.", "success", 2600);
  } catch (err) {
    showToast(
      String(err?.message || "Unable to clear operator messages."),
      "warning",
      3600,
    );
  } finally {
    State.chatPendingClear = false;
    renderChatSendState();
    if (State.chatOpen) resetChatDismissTimer();
  }
}

function toggleChatPanel() {
  if (State.chatOpen) {
    closeChatPanel();
    return;
  }
  openChatPanel();
  if (!State.chatHistoryLoaded) {
    loadChatHistory({ silent: true }).catch(() => {});
  }
}

function resetChatState() {
  clearChatDismissTimer();
  State.chatOpen = false;
  State.chatUnread = 0;
  State.chatMessages = [];
  State.chatLastReadId = 0;
  State.chatLastInboundId = 0;
  State.chatPendingSend = false;
  State.chatPendingClear = false;
  State.chatReadInFlight = false;
  State.chatPendingReadUpToId = 0;
  State.chatHistoryLoaded = false;
  if ($("chatInput")) $("chatInput").value = "";
  renderChatSendState();
  renderChatBadge();
  renderChatThread();
  closeChatPanel();
}


